insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'What is 35% of 240?', '240 का 35% क्या है?', '35% = 35/100 = 0.35. 0.35 × 240 = 84. Quicker: 10% of 240 = 24, so 35% = 24 × 3.5 = 84.', '''Percent'' means ''per 100''. p% of N = (p × N)/100. The fraction p/100 is the multiplier; multiplying any number N by it scales N down proportionally. 10% chunks are easy mental anchors — split the rate into 10s and remainders.', '35% = 35/100 = 0.35। 0.35 × 240 = 84। तेज़ तरीका: 10% of 240 = 24, अतः 35% = 24 × 3.5 = 84।', '''percent'' का मतलब ''per 100'' है। p% of N = (p × N)/100। यह fraction p/100 multiplier है जो किसी भी संख्या N को proportional रूप से scale करता है। 10% के chunks सबसे आसान mental anchor हैं — rate को 10 और शेष में बाँटें।', 'EASY', array['percentage','basic-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '84', '84', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '82', '82', false, 'Took 30% = 72 and used 5% = 10 instead of 12, giving 72 + 10 = 82.', '30% = 72 लिया और 5% को 12 की जगह 10 लिया; 72 + 10 = 82।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '96', '96', false, 'Used 40% of 240: 4 × 24 = 96, replacing the required 35%.', '35% की जगह 40% लगाया: 4 × 24 = 96।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '72', '72', false, 'Used only 30% of 240: 3 × 24 = 72, missing the extra 5%.', 'सिर्फ 30% लिया: 3 × 24 = 72; extra 5% छूट गया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'If a number is increased by 20% and then decreased by 20%, what is the net change?', 'किसी संख्या को 20% बढ़ाकर फिर 20% घटाया जाए, तो net change क्या है?', 'Use the formula: net% = a + b + (a×b)/100, where a = +20, b = −20. Net = 20 − 20 + (20)(−20)/100 = 0 − 4 = −4%. So 4% decrease.', 'Take 100 as the original. After +20%: 120. After −20% on 120: 120 × 0.80 = 96. Final = 96, drop = 4 on 100 = 4%. The two ±x% adjustments don''t cancel because the base of the second adjustment (120) is larger than the base of the first (100); the absolute decrease 24 exceeds the absolute increase 20.', 'formula: net% = a + b + (a×b)/100, जहाँ a = +20, b = −20. Net = 20 − 20 + (20)(−20)/100 = 0 − 4 = −4%। यानी 4% decrease।', '100 को मूल मानें। +20% के बाद: 120। 120 पर −20% = 120 × 0.80 = 96। Final = 96, गिरावट = 100 में से 4 = 4%। ±x% adjustments cancel नहीं होते क्योंकि दूसरे adjustment का base (120) पहले के base (100) से बड़ा है; absolute कमी 24 absolute बढ़त 20 से ज़्यादा है।', 'EASY', array['percentage','successive-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '0% (no change)', '0% (कोई बदलाव नहीं)', false, 'Common error — students subtract 20-20 = 0, but the bases differ. The 20% decrease is on the increased number (120%), not on the original.', 'common गलती — 20-20 = 0 कर दिया, लेकिन base अलग हैं। 20% decrease बढ़ी हुई संख्या (120%) पर लगता है, मूल पर नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '4% decrease', '4% की कमी', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '4% increase', '4% की बढ़त', false, 'Right magnitude, wrong direction — successive +x% and −x% always result in a net decrease, never an increase.', 'magnitude सही, दिशा गलत — successive +x% और −x% का net result हमेशा कमी होगा, बढ़त नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '40% decrease', '40% की कमी', false, 'Incorrectly added the percentages. Successive percentages compound, they don''t add.', 'percentages को जोड़ दिया। successive percentages compound होते हैं, जोड़े नहीं जाते।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'A number when increased by 25% becomes 80. What was the original number?', 'एक संख्या को 25% बढ़ाने पर 80 हो जाती है। मूल संख्या क्या थी?', 'If +25% gives 80, then 80 represents 125% of original. Original = 80 × 100/125 = 80 × 0.8 = 64.', 'Reverse-percentage problems are about identifying which side of the comparison is the ''whole'' (100%). Here ''after a 25% increase'' means the result is 125% of the start. To recover the start, divide the result by the multiplier (1.25), not by adding/subtracting 25 to the result.', '+25% पर 80 मिलता है, यानी 80 मूल के 125% के बराबर है। मूल = 80 × 100/125 = 80 × 0.8 = 64।', 'Reverse-percentage problems में पहचानना है कि comparison में ''whole'' (100%) कौन है। यहाँ ''25% बढ़ाने पर'' का मतलब result मूल का 125% है। मूल को निकालने के लिए result को multiplier (1.25) से भाग दें — न कि result में 25 जोड़ें/घटाएँ।', 'EASY', array['percentage','reverse-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '60', '60', false, 'Subtracted 25 from 80 = 55, then approximated up. Wrong because 25% of original ≠ 25 absolute.', '80 से 25 घटाकर 55 निकाला और round किया। गलत क्योंकि मूल का 25% absolute 25 नहीं है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '55', '55', false, 'Subtracted 25 directly from 80 — confusing 25% of original with 25 units.', '80 में से 25 घटाया — मूल का 25% को 25 units समझा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '64', '64', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '100', '100', false, 'Subtracted 25% from 80: 80 − 20 = 60, then over-corrected. The relationship is 80 = 1.25 × x, so x = 64.', '80 से 20 घटाया, फिर over-correct कर दिया। सही: 80 = 1.25 × x, अतः x = 64।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, '60% of a number is 144. What is 75% of the same number?', 'किसी संख्या का 60% = 144 है। उसी संख्या का 75% क्या है?', 'Ratio shortcut: 75% / 60% = 75/60 = 5/4. So 75% = 144 × 5/4 = 180. No need to find the number first.', 'Both 60% and 75% are different fractions of the same whole. Their ratio (75/60 = 5/4) tells you directly how the second value relates to the first. This ''cross-percent'' shortcut saves a step over finding the original number (240) and then 75% of it (180).', 'Ratio shortcut: 75% / 60% = 75/60 = 5/4। तो 75% = 144 × 5/4 = 180। मूल संख्या निकालने की ज़रूरत नहीं।', '60% और 75% दोनों एक ही whole के अलग-अलग fractions हैं। उनका ratio (75/60 = 5/4) सीधे बताता है कि दूसरा value पहले से कितना है। यह ''cross-percent'' shortcut मूल संख्या (240) निकालने और फिर 75% (180) निकालने का step बचाता है।', 'EASY', array['percentage','ratio-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '180', '180', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '240', '240', false, 'This is the original number (60% × 240 = 144), not 75% of it.', 'यह मूल संख्या है (60% × 240 = 144), उसका 75% नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '168', '168', false, 'Added 24 (15 increase ratio) to 144 — used absolute additive logic instead of ratio.', '144 में 24 जोड़ा (15 increase ratio) — ratio की जगह additive logic लगाया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '192', '192', false, 'Added 48 = 144 × 1/3, mistaking 75/60 for 4/3 instead of 5/4.', '144 × 1/3 = 48 जोड़ा, 75/60 को 4/3 समझ लिया, सही 5/4 है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'Ramesh spends 75% of his salary. If his salary is increased by 20% and his expenses by 10%, by what percent do his savings change?', 'रमेश अपनी salary का 75% खर्च करता है। यदि उसकी salary 20% बढ़े और expenses 10% बढ़ें, तो savings कितने प्रतिशत बदलेंगी?', 'Take salary = 100, so expenses = 75 and savings = 25. New salary = 120, new expenses = 75 × 1.10 = 82.5. New savings = 120 − 82.5 = 37.5. Change = (37.5 − 25)/25 = 50%.', 'Savings are the residual: salary minus expenses. When two different bases (here 100 and 75) grow at different rates, the residual''s percent change depends on the absolute changes, not the percent changes. Always assume a clean base (e.g., 100), compute absolute amounts, and only then convert the change in the residual back to a percent.', 'salary = 100 मानें, expenses = 75, savings = 25। नई salary = 120, नई expenses = 75 × 1.10 = 82.5। नई savings = 120 − 82.5 = 37.5। Change = (37.5 − 25)/25 = 50%।', 'Savings residual हैं: salary − expenses। जब दो अलग bases (यहाँ 100 और 75) अलग rates पर बढ़ते हैं, तो residual का percent change percent changes पर नहीं, absolute changes पर निर्भर करता है। हमेशा clean base (e.g. 100) मान लें, absolute amounts निकालें, फिर residual के change को percent में बदलें।', 'MEDIUM', array['percentage','savings-expenses','salary-expenses','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Increase by 50%', '50% की बढ़त', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Increase by 10%', '10% की बढ़त', false, 'Subtracted 10 from 20 — but salary and expenses are different bases, you can''t compare percentages directly.', '20 से 10 घटाया — पर salary और expenses के base अलग हैं, percentages को सीधे compare नहीं कर सकते।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Increase by 30%', '30% की बढ़त', false, 'Added 20 + 10 = 30 — wrong direction, expenses cut savings, they don''t add.', '20 + 10 = 30 जोड़ा — दिशा गलत, expenses savings कम करते हैं, जोड़ते नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Increase by 25%', '25% की बढ़त', false, 'Found savings increase = 12.5, then divided by 50 instead of original savings 25: 12.5/50 = 25%.', 'savings increase = 12.5 निकाला, फिर original savings 25 की जगह 50 से divide किया: 12.5/50 = 25%।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'If the price of sugar increases by 25%, by what percentage should a family reduce its consumption to keep the expenditure on sugar unchanged?', 'यदि चीनी की कीमत 25% बढ़ जाए, तो परिवार को consumption कितने प्रतिशत घटानी चाहिए कि sugar पर expenditure same रहे?', 'Formula: required reduction% = (rise%)/(100 + rise%) × 100 = 25/125 × 100 = 20%.', 'Expenditure = price × consumption. To keep it constant when price multiplies by 1.25, consumption must multiply by 1/1.25 = 0.80, i.e., reduce by 20%. The asymmetry between 25% rise and 20% cut comes from the base inversion: rising 25% on the smaller base, cutting 20% on the larger base.', 'formula: needed cut% = (rise%)/(100 + rise%) × 100 = 25/125 × 100 = 20%।', 'Expenditure = price × consumption. इसे constant रखने के लिए जब price 1.25 गुना हो, तो consumption को 1/1.25 = 0.80 गुना करना होगा, यानी 20% कम। 25% बढ़त और 20% कमी की asymmetry base के बदलने से आती है: छोटे base पर 25% बढ़त, बड़े base पर 20% कमी।', 'MEDIUM', array['percentage','price-consumption','reverse-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '25%', '25%', false, 'Symmetric instinct — but cutting consumption by 25% only offsets a small price rise, not 25%. Bases differ.', 'symmetric instinct से — पर 25% consumption cut छोटी price rise को offset करता है, 25% को नहीं। bases अलग।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '15%', '15%', false, 'Used 25% price rise minus a 10-point adjustment to get 15%. But 1.25 × 0.85 = 1.0625, so expenditure still rises by 6.25%.', '25% price rise में से 10-point adjustment घटाकर 15% लिया। पर 1.25 × 0.85 = 1.0625, इसलिए expenditure फिर भी 6.25% बढ़ता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '30%', '30%', false, 'Overcompensated — 30% consumption cut would leave expenditure lower than original.', 'Overcompensate — 30% consumption cut से expenditure मूल से कम हो जाता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 6, 'In an election between two candidates, the loser polled 45% of total valid votes and lost by 4000 votes. How many total valid votes were cast?', 'दो उम्मीदवारों के बीच चुनाव में हारने वाले को 45% valid votes मिले और वह 4000 votes से हारा। कुल valid votes कितने थे?', 'Loser got 45%, winner got 55%. Margin = 55% − 45% = 10% of total = 4000 votes. So total = 4000/0.10 = 40000.', 'When two parties split 100% and one has p%, the other has (100−p)%. The ''margin'' is the absolute difference (100−2p)%. Convert any margin in absolute units (here 4000 votes) to total by dividing by the margin''s fractional value.', 'हारने वाले को 45%, जीतने वाले को 55%। margin = 55% − 45% = total का 10% = 4000 votes। तो total = 4000/0.10 = 40000।', 'जब दो parties 100% बाँटें और एक को p% मिले, तो दूसरे को (100−p)%। margin absolute difference (100−2p)% होता है। किसी भी margin को absolute units (यहाँ 4000 votes) से total तक पहुँचाने के लिए margin के fractional value से भाग दें।', 'MEDIUM', array['percentage','elections','percent-difference','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20000', '20000', false, 'Used (4000/20%) but with wrong margin — 4000 = 10% of total, not 20%.', '(4000/20%) लगाया पर margin गलत — 4000 = total का 10%, 20% नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '40000', '40000', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '8000', '8000', false, 'Used 4000 ÷ 0.5 — confused half-margin shortcut with the percent gap.', '4000 ÷ 0.5 लगाया — half-margin shortcut को percent gap समझ लिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '44000', '44000', false, 'Computed 4000/9% (treating 9% wrongly as the margin). Margin is 10%.', '4000/9% लगाया (9% margin गलत)। सही margin 10% है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 7, 'The population of a town increased from 20000 to 23000. Find the percentage increase.', 'एक कस्बे की जनसंख्या 20000 से 23000 हो गई। percentage increase निकालिए।', 'Increase = 23000 − 20000 = 3000. % increase = 3000/20000 × 100 = 15%.', 'Percentage change is always relative to the OLD value (the base). Formula: %change = (new − old)/old × 100. Dividing by the new value (23000) gives the wrong answer because that''s not the base of the increase — the increase happened from 20000.', 'increase = 23000 − 20000 = 3000। % increase = 3000/20000 × 100 = 15%।', 'Percentage change हमेशा OLD value (base) के सापेक्ष होता है। Formula: %change = (new − old)/old × 100। नई value (23000) से भाग देने पर answer गलत आता है क्योंकि वह base नहीं है — बढ़त 20000 से हुई है।', 'EASY', array['percentage','growth-rate','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '13%', '13%', false, 'Used (3000/23000)×100 — divided by the new value instead of the old.', '(3000/23000)×100 लगाया — नए value से भाग दिया, पुराने से नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '15%', '15%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '10%', '10%', false, 'Divided 3000 by 30000 instead of 20000: 3000/30000 × 100 = 10%.', '3000 को 20000 की जगह 30000 से divide किया: 3000/30000 × 100 = 10%।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '1.15%', '1.15%', false, 'Computed 3000/20000 = 0.15 but forgot to multiply by 100 to convert to %.', '3000/20000 = 0.15 निकाला पर × 100 भूल गए।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'A''s salary is 25% more than B''s salary. By what percentage is B''s salary less than A''s?', 'A की salary B की salary से 25% अधिक है। B की salary A की salary से कितने प्रतिशत कम है?', 'Shortcut: B<A by (25/125) × 100 = 20%. Generally, if X is x% more than Y, Y is x/(100+x) × 100% less than X.', 'Take B = 100, then A = 125. Difference = 25. To express the difference as a percent of A: 25/125 = 20%. The reason 25% ≠ 20% is the base shift: when comparing ''A more than B'' the base is B; when comparing ''B less than A'' the base is A. Larger base means smaller percent.', 'shortcut: B<A by (25/125) × 100 = 20%। सामान्य: यदि X, Y से x% अधिक है, तो Y, X से x/(100+x) × 100% कम है।', 'B = 100 मानें, A = 125। अंतर = 25। A के percent में: 25/125 = 20%। 25% ≠ 20% होने का कारण base shift है: ''A from B more'' में base B है; ''B from A less'' में base A। बड़ा base = छोटा percent।', 'MEDIUM', array['percentage','comparison-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '25%', '25%', false, 'Common error: assumed symmetry. But the bases differ — 25% of B (smaller) ≠ 25% of A (larger).', 'common गलती: symmetry मान ली। पर bases अलग हैं — B (छोटा) का 25% ≠ A (बड़ा) का 25%।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '30%', '30%', false, 'Overcorrection — sensed asymmetry but went the wrong way. Less salary''s percent gap is smaller, not bigger.', 'Overcorrect — asymmetry पकड़ी पर दिशा गलत। कम salary का percent gap छोटा होता है, बड़ा नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '15%', '15%', false, 'Used 25 × 0.6 — wrong shortcut. Correct shortcut is 25/(100+25) × 100 = 20.', '25 × 0.6 लगाया — shortcut गलत। सही: 25/(100+25) × 100 = 20।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 9, 'An article is marked at ₹500. After a discount of 10% and an additional 5% off on the discounted price, what is the final price?', 'एक वस्तु का marked price ₹500 है। पहले 10% discount, फिर discounted price पर 5% और discount। अंतिम कीमत क्या है?', 'Final = 500 × 0.90 × 0.95 = 500 × 0.855 = ₹427.50. Equivalent single discount = 1 − 0.855 = 14.5%.', 'Successive percentage changes multiply, they don''t add. Each later discount applies to the already-reduced price. Equivalent single rate for two successive discounts a%, b% is: 1 − (1−a/100)(1−b/100). Here = 1 − 0.90 × 0.95 = 0.145 = 14.5%, less than 10+5 = 15%.', 'Final = 500 × 0.90 × 0.95 = 500 × 0.855 = ₹427.50। equivalent single discount = 1 − 0.855 = 14.5%।', 'Successive percentage changes multiply होते हैं, जुड़ते नहीं। हर अगला discount पहले से कम हुई price पर लगता है। दो successive discounts a%, b% का equivalent single rate: 1 − (1−a/100)(1−b/100)। यहाँ = 1 − 0.90 × 0.95 = 0.145 = 14.5%, जो 10+5 = 15% से कम है।', 'MEDIUM', array['percentage','successive-discount','discount','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹425.00', '₹425.00', false, 'Subtracted 15% directly from ₹500 — but successive discounts compound, they don''t add.', '₹500 में से 15% सीधे घटाया — successive discounts compound होते हैं, जोड़े नहीं जाते।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹427.50', '₹427.50', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹450.00', '₹450.00', false, 'Computed only the first discount and stopped.', 'केवल पहला discount निकाला, दूसरा भूल गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹475.00', '₹475.00', false, 'Took only 5% off the marked price — applied wrong discount.', 'marked price से सिर्फ 5% घटाया — wrong discount लगाया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'If 70% of students pass an exam and 24 students fail, how many students appeared?', 'यदि 70% छात्र pass हों और 24 छात्र fail हों, तो कुल कितने छात्र appeared थे?', 'Pass% = 70 ⇒ Fail% = 30. 30% of total = 24 ⇒ total = 24 ÷ 0.30 = 80.', 'Pass and fail are mutually exclusive and cover all candidates, so they sum to 100%. Whenever you have an absolute count tied to a percent, divide the count by the percent''s fractional value (here 0.30, NOT 0.70 — because 24 is the count of failers, not passers).', 'Pass% = 70 ⇒ Fail% = 30। total का 30% = 24 ⇒ total = 24 ÷ 0.30 = 80।', 'Pass और fail mutually exclusive हैं और सब को cover करते हैं, अतः sum 100%। जब absolute count किसी percent से जुड़ी हो, तो count को percent के fractional value से भाग दें (यहाँ 0.30, 0.70 नहीं — क्योंकि 24 fail हुए हैं, pass नहीं)।', 'EASY', array['percentage','complement-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '60', '60', false, 'Used 24 ÷ 0.40 — used wrong fail percentage.', '24 ÷ 0.40 लगाया — fail % गलत।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '80', '80', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '100', '100', false, 'Used 24/24 = 1, then converted it to 100; the fail fraction should be 30%, so total = 24/0.30 = 80.', '24/24 = 1 करके 100 लिया; fail fraction 30% है, इसलिए total = 24/0.30 = 80।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '120', '120', false, 'Used 24 ÷ 0.20 — used 20% fail rate, but actual is 30%.', '24 ÷ 0.20 लगाया — 20% fail माना, सही 30%।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 11, 'A''s income is 20% less than B''s. B''s income is 25% less than C''s. A''s income is what percent of C''s?', 'A की income B की income से 20% कम है। B की income C की income से 25% कम है। A की income C की income का कितने प्रतिशत है?', 'Take C = 100. B = 100 × 0.75 = 75. A = 75 × 0.80 = 60. So A = 60% of C.', 'Chain percentages of the form ''X is x% less than Y, Y is y% less than Z'' compose multiplicatively: A/C = (A/B)(B/C) = (1−x/100)(1−y/100). Adding x and y is wrong because each percent is on a different base in the chain.', 'C = 100 मानें। B = 100 × 0.75 = 75। A = 75 × 0.80 = 60। तो A = C का 60%।', '''X, Y से x% कम है, Y, Z से y% कम है'' इस chain में percentages गुणा से compose होते हैं: A/C = (A/B)(B/C) = (1−x/100)(1−y/100)। x + y जोड़ना गलत है क्योंकि chain में हर percent अलग base पर है।', 'HARD', array['percentage','chain-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '55%', '55%', false, 'Subtracted 20+25 = 45% directly from 100% — wrong, compound effects.', '20+25 = 45% सीधे घटाया — गलत, compound effect।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '60%', '60%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '65%', '65%', false, 'Subtracted 20 and 25 from 100, then added back 10: 100 - 45 + 10 = 65. The overlap correction should be 5, so A is 60% of C.', '100 से 20 और 25 घटाकर 10 वापस जोड़ा: 100 - 45 + 10 = 65। correction 5 होना चाहिए, इसलिए A = 60% of C।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '75%', '75%', false, 'Took only the B-vs-C step (75%) and forgot the A-vs-B step.', 'केवल B-vs-C step (75%) लिया, A-vs-B भूले।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 12, 'In a class of 50 students, 60% are boys. If 8 girls are absent on a particular day, what percent of the class present is girls?', '50 छात्रों की class में 60% लड़के हैं। एक दिन 8 लड़कियाँ absent हैं — present class में लड़कियाँ कितने प्रतिशत हैं?', 'Total = 50, boys = 30, girls = 20. Absent girls = 8 ⇒ present girls = 12. Present class = 50 − 8 = 42. % = 12/42 × 100 ≈ 28.57%. Rounded to one decimal, this is 28.6%.', 'When the population''s composition changes (here through absences), recompute the relevant base. The ''percent present girls'' takes ''present girls'' as the numerator and ''present total'' (not original total) as the denominator. The boys count stays at 30 because no boys are absent.', 'total = 50, लड़के = 30, लड़कियाँ = 20। absent लड़कियाँ = 8 ⇒ present लड़कियाँ = 12। present class = 50 − 8 = 42। % = 12/42 × 100 ≈ 28.57%। एक decimal तक round करने पर यह 28.6% है।', 'जब population का composition बदले (यहाँ absences से), तो relevant base फिर से निकालें। ''percent present girls'' का numerator ''present girls'' और denominator ''present total'' (मूल total नहीं) है। लड़के 30 वही रहे क्योंकि कोई लड़का absent नहीं।', 'MEDIUM', array['percentage','ratio-percentage','absenteeism','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20%', '20%', false, 'Used 12/60 instead of 12/42 — divided present girls by total class, not present class.', '12/60 लगाया, सही 12/42 — divisor present class नहीं, total लिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Approx 28.6%', 'लगभग 28.6%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '40%', '40%', false, 'This is the original girls% — but absent girls reduced it.', 'मूल girls% यही है — पर absent ने इसे कम कर दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '32%', '32%', false, 'Used 37.5 as the present-class base instead of 42: 12/37.5 × 100 = 32%.', 'present class base 42 की जगह 37.5 लिया: 12/37.5 × 100 = 32%।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 13, 'The price of a commodity rose by 30%. The expenditure on it increased by only 8%. By what percentage did consumption decrease?', 'एक commodity की कीमत 30% बढ़ी। उस पर expenditure सिर्फ 8% बढ़ा। consumption कितने प्रतिशत घटी?', 'expenditure = price × consumption. So consumption_ratio = expenditure_ratio / price_ratio = 1.08 / 1.30 ≈ 0.8308. Drop ≈ (1 − 0.8308) × 100 ≈ 16.9%.', 'Expenditure is the product of price and consumption. If price rises by p% and expenditure rises by e%, the consumption multiplier is (1 + e/100)/(1 + p/100). The drop in consumption is whatever short-fall keeps expenditure from rising as much as the price did.', 'expenditure = price × consumption। तो consumption_ratio = expenditure_ratio / price_ratio = 1.08/1.30 ≈ 0.8308। drop ≈ (1 − 0.8308) × 100 ≈ 16.9%।', 'Expenditure = price × consumption। यदि price p% बढ़े और expenditure e% बढ़े, तो consumption multiplier = (1 + e/100)/(1 + p/100)। consumption में जितनी कमी आए, उतनी ही expenditure की rise को price-rise से कम रखती है।', 'HARD', array['percentage','expenditure','price-consumption','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Approx 16.9%', 'लगभग 16.9%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '22%', '22%', false, 'Subtracted 8 from 30 directly — but expenditure = price × consumption, ratios involved.', '30 में से 8 घटाया — पर expenditure = price × consumption, ratios लगते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '20%', '20%', false, 'Used price ratio 1.35 instead of 1.30: 1.08/1.35 = 0.80, giving a 20% drop.', 'price ratio 1.30 की जगह 1.35 लिया: 1.08/1.35 = 0.80, इसलिए 20% drop।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '30%', '30%', false, 'Cancelled the price rise entirely — would mean expenditure didn''t change.', 'price rise पूरा cancel कर दिया — पर तब expenditure वही रहती।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 14, 'A number is increased by 50% and then decreased by 50%. The net change is:', 'किसी संख्या को 50% बढ़ाया जाए और फिर 50% घटाया जाए। net change है:', 'Formula: net% = a + b + (a×b)/100 = 50 + (−50) + (50)(−50)/100 = 0 − 25 = −25%. So 25% decrease.', 'Take 100 → +50% → 150 → −50% → 75. Drop = 25 on 100 = 25%. The asymmetry comes from cutting on a larger base (150) than you grew on (100). General rule: ±x% successive on the same number always nets to a decrease of (x²/100)%.', 'Formula: net% = a + b + (a×b)/100 = 50 + (−50) + (50)(−50)/100 = 0 − 25 = −25%। यानी 25% की कमी।', '100 → +50% → 150 → −50% → 75। drop = 100 में से 25 = 25%। asymmetry का कारण: कमी बड़े base (150) पर लगी, बढ़त छोटे (100) पर। सामान्य नियम: एक ही संख्या पर successive ±x% का net हमेशा (x²/100)% की कमी।', 'EASY', array['percentage','successive-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '0% (no change)', '0% (कोई बदलाव नहीं)', false, 'Symmetry trap — 50−50 doesn''t equal zero because bases differ at each step.', 'symmetry trap — 50−50 = 0 नहीं होता क्योंकि हर step पर base अलग है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '25% decrease', '25% की कमी', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '25% increase', '25% की बढ़त', false, 'Right magnitude, wrong direction. Successive ±x always nets to a decrease.', 'magnitude सही, दिशा गलत। successive ±x का net हमेशा कमी होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '50% decrease', '50% की कमी', false, 'Took only the second step. The first step inflated the base.', 'केवल दूसरा step लिया। पहले step ने base बढ़ा दिया था।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 15, 'An article bought for ₹800 is sold for ₹960. Find the gain percentage.', 'एक वस्तु ₹800 में खरीदकर ₹960 में बेची गई। gain प्रतिशत क्या है?', 'Gain = SP − CP = 960 − 800 = 160. Gain% = 160/800 × 100 = 20%.', 'Gain percent always uses cost price as the base: gain% = (SP−CP)/CP × 100. Using SP as the denominator answers a different question (margin %, not gain %) — the values differ whenever there is any non-zero profit or loss.', 'Gain = SP − CP = 960 − 800 = 160। Gain% = 160/800 × 100 = 20%।', 'Gain percent हमेशा cost price पर लगता है: gain% = (SP−CP)/CP × 100। SP को denominator बनाना गलत है — वह margin% निकालता है (अलग धारणा)।', 'EASY', array['profit-loss','gain-percentage','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '16.67%', '16.67%', false, 'Divided gain 160 by SP 960 (not CP 800): 160/960 = 16.67%. This answers margin% on SP, not gain% on CP.', '160 को SP 960 से भाग दिया: 160/960 = 16.67%। यह margin% (SP पर) है, gain% (CP पर) नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '25%', '25%', false, 'Subtracted gain 160 from CP first, then used 640 as the denominator: 160/(800−160) = 160/640 = 25%. The denominator must stay CP 800.', 'CP 800 में से gain 160 घटाकर denominator 640 लिया: 160/640 = 25%। Denominator हमेशा CP 800 ही रहेगा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '120%', '120%', false, 'Computed SP/CP × 100 = 960/800 × 100 = 120%. This is the selling-price multiplier expressed as a percent (= 1 + gain%), not the gain% itself.', 'SP/CP × 100 = 960/800 × 100 = 120% लिया। यह SP multiplier % में है (1 + gain%), gain% नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 16, 'The cost price of an article is ₹500. The shopkeeper marks it up by 20%. What is the marked price?', 'एक वस्तु का cost price ₹500 है। दुकानदार उस पर 20% markup लगाता है। marked price क्या है?', 'MP = CP × (1 + markup%) = 500 × 1.20 = ₹600.', 'Markup is measured as a percentage of cost price: a 20% markup adds 20% of CP (₹100) to CP (₹500), yielding MP ₹600. Markup and discount are inverse direction operations — they move the price away from CP and away from MP respectively.', 'MP = CP × (1 + markup%) = 500 × 1.20 = ₹600।', 'Markup cost price का percent होता है: 20% markup = CP का 20% (₹100) = ₹500 में जुड़कर MP ₹600। Markup CP से बढ़ाता है, discount MP से घटाता है — दिशा विपरीत है।', 'EASY', array['profit-loss','markup','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹520', '₹520', false, 'Added 20 directly instead of 20% of 500; 20% of 500 = 100, giving ₹600, not ₹520.', '500 में 20 सीधे जोड़ा; 20% of 500 = 100 होता, अतः ₹600 सही है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹600', '₹600', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹700', '₹700', false, 'Doubled the markup rate to 40%: 500 × 1.40 = 700. The question states 20%, not 40%.', 'markup rate को दोगुना करके 40% लगाया: 500 × 1.40 = 700। Question में 20% दिया है, 40% नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹400', '₹400', false, 'Computed 500 × 0.80 — took a 20% discount direction instead of a 20% markup.', '500 × 0.80 लगाया — markup की जगह 20% discount की दिशा में किया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 17, 'The marked price of a shirt is ₹600. After a 15% discount, what is the selling price?', 'एक shirt का marked price ₹600 है। 15% discount के बाद selling price क्या होगी?', 'SP = MP × (1 − discount%) = 600 × 0.85 = ₹510. Shortcut: 10% of 600 = 60, 5% = 30, total = 90 off.', 'Discount is a percentage of the marked price (not of CP). SP = MP − discount. When you flip the operation to a multiplier (0.85 here), the arithmetic collapses to one step — handy in exam conditions.', 'SP = MP × (1 − discount%) = 600 × 0.85 = ₹510। shortcut: 10% of 600 = 60, 5% = 30, कुल 90 घटाएँ।', 'Discount marked price का percent है (CP का नहीं)। SP = MP − discount। multiplier (यहाँ 0.85) में बदलने से एक step में हल हो जाता है।', 'EASY', array['profit-loss','discount','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹510', '₹510', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹585', '₹585', false, 'Subtracted 15 (the percent number, not 15% of the amount) directly from 600: 600 − 15 = 585.', '600 में से 15 (percent की संख्या) सीधे घटाया, न कि 15% of 600 = 90: 600 − 15 = 585।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹540', '₹540', false, 'Applied a 10% discount (600 × 0.90 = 540), not the 15% stated in the question.', '600 × 0.90 = 540 लगाया — 10% discount, जबकि question में 15% है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹690', '₹690', false, 'Added 15% instead of subtracting: 600 × 1.15 = 690. Direction flipped — discount subtracts, not adds.', 'Discount को घटाने की बजाय जोड़ा: 600 × 1.15 = 690। Discount हमेशा घटता है, जुड़ता नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 18, 'An article bought for ₹900 is sold for ₹810. Find the loss percentage.', 'एक वस्तु ₹900 में खरीदकर ₹810 में बेची गई। loss प्रतिशत क्या है?', 'Loss = CP − SP = 90. Loss% = 90/900 × 100 = 10%.', 'Loss% uses CP as the base just like gain%. Sign is captured by the fact that SP < CP; the formula (CP−SP)/CP × 100 returns a positive percentage representing the shortfall relative to cost.', 'Loss = CP − SP = 90। Loss% = 90/900 × 100 = 10%।', 'Loss% में भी base CP होता है (gain% की तरह)। Formula (CP−SP)/CP × 100; positive number shortfall दर्शाता है।', 'EASY', array['profit-loss','loss-percentage','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '10%', '10%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '11.11%', '11.11%', false, 'Divided loss 90 by SP 810 (not CP 900): 90/810 = 11.11%. Loss% always uses CP as the base.', '90 को SP 810 से भाग दिया: 90/810 = 11.11%। Loss% हमेशा CP पर।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '9%', '9%', false, 'Substituted denominator 1000 for CP 900 (mental shortcut): 90/1000 = 9%. Correct CP is 900, not 1000.', 'CP 900 की जगह 1000 रख दिया: 90/1000 = 9%। सही CP 900 है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '90%', '90%', false, 'Computed SP/CP × 100 = 810/900 × 100 = 90%. This is SP as a percent of CP (= 100 − loss%), not the loss% itself.', 'SP/CP × 100 = 810/900 × 100 = 90% लगाया। यह CP के percent में SP है (= 100 − loss%), loss% नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 19, 'A toy is sold for ₹660 at a gain of 10%. What was the cost price?', 'एक खिलौना ₹660 में 10% gain पर बेचा गया। cost price क्या थी?', 'SP = CP × (1 + gain%) ⇒ CP = SP / 1.10 = 660/1.10 = ₹600.', 'Reverse-percentage: given a post-gain SP, the CP is recovered by dividing by the multiplier (1 + gain%). Subtracting the gain% from SP is a common error — it uses SP as the base of the gain, but gain is measured on CP.', 'SP = CP × (1 + gain%) ⇒ CP = SP/1.10 = 660/1.10 = ₹600।', 'Reverse-percentage: gain-post SP से CP निकालने के लिए multiplier (1 + gain%) से भाग दें। SP में से gain% घटाना गलत है — gain का base CP है, SP नहीं।', 'EASY', array['profit-loss','reverse-calculation','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹594', '₹594', false, 'Subtracted 10% of SP from SP: 660 − 66 = 594. CP formula is SP/(1 + gain%), not SP − gain%·SP.', 'SP में से 10% of SP घटाया: 660 − 66 = 594। CP formula SP/(1 + gain%) है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹600', '₹600', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹726', '₹726', false, 'Added 10% of SP to SP: 660 × 1.10 = 726. Treated SP as the base of gain in the wrong direction.', 'SP में 10% of SP जोड़ दिया: 660 × 1.10 = 726। Gain base को गलत दिशा में लगाया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹550', '₹550', false, 'Applied reverse formula with 20% in place of 10%: 660/1.20 = 550. Read the gain rate wrong.', 'Reverse formula में 10% की जगह 20% लगाया: 660/1.20 = 550। Gain rate गलत पढ़ा।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'A trader bought a machine for ₹1,200 and sold it at a 15% loss. Find the selling price.', 'एक व्यापारी ने ₹1,200 में एक machine खरीदी और 15% loss पर बेची। selling price क्या है?', 'SP = CP × (1 − loss%) = 1200 × 0.85 = ₹1,020.', 'Loss shifts SP below CP. Multiplying CP by (1 − loss%) gives SP in one step, analogous to how (1 + gain%) handles the gain case. Subtracting the percent value directly (15) from the amount (1200) conflates ''percent'' with ''amount''.', 'SP = CP × (1 − loss%) = 1200 × 0.85 = ₹1,020।', 'Loss में SP, CP से कम हो जाता है। CP × (1 − loss%) एक step में SP देता है। percent value को सीधे amount से घटाना ग़लत है।', 'EASY', array['profit-loss','loss','direct-calculation','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹1,020', '₹1,020', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹1,185', '₹1,185', false, 'Subtracted 15 (not 15% = ₹180) from CP.', 'CP में से 15 घटाया (15% = ₹180 घटाना था)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹1,380', '₹1,380', false, 'Added the loss instead of subtracting — wrong direction.', 'Loss जोड़ दिया, घटाया नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹1,080', '₹1,080', false, 'Used 10% loss (multiplied by 0.90), not 15%.', '10% loss लगाया, 15% नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 21, 'The marked price of a bag is ₹1,000 and it is sold for ₹850. Find the discount percentage.', 'एक bag का marked price ₹1,000 है और यह ₹850 में बिकता है। discount प्रतिशत क्या है?', 'Discount = MP − SP = 150. Discount% = 150/1000 × 100 = 15%.', 'Discount% is always expressed relative to the marked price, not the selling price. Using SP as the denominator inflates the number because SP < MP, so dividing by the smaller denominator gives a larger apparent rate.', 'Discount = MP − SP = 150। Discount% = 150/1000 × 100 = 15%।', 'Discount% हमेशा marked price पर होता है, SP पर नहीं। SP से भाग देने पर denominator छोटा होता है (SP<MP) अतः answer बड़ा आता है — गलत।', 'EASY', array['profit-loss','discount','reverse-calculation','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '15%', '15%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '17.65%', '17.65%', false, 'Divided discount 150 by SP 850 (not MP 1000): 150/850 = 17.65%. Discount% must use MP as the base.', 'Discount 150 को SP 850 से भाग दिया: 150/850 = 17.65%। Discount% का base MP होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '13.04%', '13.04%', false, 'Used MP + discount = 1150 as denominator: 150/1150 = 13.04%. The denominator is just MP, not MP + discount.', 'Denominator में MP + discount = 1150 लिया: 150/1150 = 13.04%। Denominator सिर्फ MP होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '85%', '85%', false, 'Computed SP/MP × 100 = 850/1000 × 100 = 85%. This is the fraction paid (= 100 − discount%), not the discount%.', 'SP/MP × 100 = 85% लगाया — यह pay किया गया अंश है (= 100 − discount%), discount% नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 22, 'Which option represents a larger absolute profit: selling at 20% gain on a CP of ₹200, or selling at 15% gain on a CP of ₹300?', 'किसमें absolute profit ज़्यादा है: CP ₹200 पर 20% gain, या CP ₹300 पर 15% gain?', 'Compute each: 20% of 200 = 40, 15% of 300 = 45. 45 > 40.', 'Percentages alone don''t compare absolute profits — the base matters. A smaller percent on a larger base can produce more absolute profit. Always multiply the percent by the amount before comparing.', 'हर एक निकालें: 200 का 20% = 40, 300 का 15% = 45। 45 > 40।', 'Percentage अकेले absolute profit compare नहीं करता — base मायने रखता है। बड़े base पर छोटा percent बड़ा profit दे सकता है।', 'EASY', array['profit-loss','comparison','percent-vs-absolute','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20% of ₹200', '₹200 का 20%', false, '20% of 200 = 40, which is less than 15% of 300 = 45.', '200 का 20% = 40; 300 का 15% = 45 — 40 < 45।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '15% of ₹300', '₹300 का 15%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both equal', 'दोनों बराबर', false, 'Incorrect assumption; do the arithmetic: 40 ≠ 45.', 'गलत मान्यता; 40 ≠ 45।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Can''t compare without more info', 'जानकारी कम है, compare नहीं कर सकते', false, 'Both percentages are tied to specific amounts — a definite comparison is possible.', 'दोनों percentages specific amounts से जुड़े हैं — comparison हो सकता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 23, 'A watch is marked at ₹2,000. The shopkeeper offers a 10% discount, then a further 5% on the reduced price. What is the final selling price?', 'एक watch का marked price ₹2,000 है। दुकानदार पहले 10% discount देता है, फिर reduced price पर 5% और। अंतिम selling price क्या है?', 'SP = 2000 × 0.90 × 0.95 = 2000 × 0.855 = ₹1,710. Equivalent single discount = 14.5%.', 'Successive discounts multiply: final factor = (1 − d₁/100)(1 − d₂/100). The equivalent single rate is always smaller than the sum (here 14.5% < 15%) because the second discount applies to an already-shrunk base.', 'SP = 2000 × 0.90 × 0.95 = 2000 × 0.855 = ₹1,710। equivalent single = 14.5%।', 'Successive discounts multiply होते हैं: factor = (1 − d₁/100)(1 − d₂/100)। Equivalent single हमेशा sum से कम (यहाँ 14.5% < 15%)।', 'MEDIUM', array['profit-loss','discount','successive-discount','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹1,700', '₹1,700', false, 'Subtracted 15% directly from 2000 — successive discounts compound, they don''t add.', '2000 से 15% सीधे घटाया — successive discounts compound होते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹1,710', '₹1,710', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹1,800', '₹1,800', false, 'Only applied the first discount (10% → 1800); missed the second 5%.', 'सिर्फ पहला discount (10% → 1800) लगाया; दूसरा 5% छूट गया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹1,690', '₹1,690', false, 'Applied 5% on the original 2000 (not on 1800) for the second step.', '5% को 1800 के बजाय 2000 पर लगाया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 24, 'A store offers two successive discounts of 20% and 10%. What is the equivalent single discount percentage?', 'एक store दो successive discounts देता है: 20% और 10%। equivalent single discount प्रतिशत क्या है?', 'Equivalent single = 1 − 0.80 × 0.90 = 1 − 0.72 = 0.28 = 28%. Formula: a + b − (a×b)/100 = 20 + 10 − 2 = 28.', 'For two successive discounts a% and b% the overall multiplier is (1 − a/100)(1 − b/100). Expanding gives 1 − a/100 − b/100 + ab/10000. The equivalent single discount is a + b − ab/100 (in percent). The ab/100 ''correction'' term explains why successive discounts always beat the user (the combined rate is less than the sum).', 'equivalent single = 1 − 0.80 × 0.90 = 1 − 0.72 = 0.28 = 28%। formula: a + b − (a×b)/100 = 20 + 10 − 2 = 28।', 'दो successive discounts a%, b% का overall multiplier (1−a/100)(1−b/100) होता है। equivalent single = a + b − ab/100। यह correction term बताता है कि successive discount हमेशा sum से कम होता है।', 'MEDIUM', array['profit-loss','successive-discount','equivalent-single','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '30%', '30%', false, 'Added 20 + 10 — successive percentages compound, they don''t sum.', '20+10 जोड़ दिया — successive percentages compound होते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '28%', '28%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '25%', '25%', false, 'Close but computed 20 + 10 − (20×10)/200 with wrong divisor; correct formula uses /100.', 'formula में divisor 200 लगाया; सही /100 है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '32%', '32%', false, 'Overshot: multiplied factors 0.80 × 0.88 mistakenly (wrong second factor).', 'second factor गलत ले लिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 25, 'Two articles are sold for ₹960 each. On one the trader gains 20%, on the other he loses 20%. What is his overall profit or loss percentage?', 'दो articles ₹960-₹960 में बिकते हैं। एक पर 20% gain, दूसरे पर 20% loss हुआ। overall profit/loss प्रतिशत क्या है?', 'Shortcut: whenever SPs are equal and the two percentages are the same x%, overall loss = (x/10)² = (20/10)² = 4%.', 'CP of the 20%-gain article = 960/1.20 = 800. CP of the 20%-loss article = 960/0.80 = 1200. Total CP = 2000, total SP = 1920. Loss = 80 on 2000 = 4%. The asymmetry comes from the CPs differing: the loss article''s CP is higher (so the percent loss is on a bigger base) than the gain article''s.', 'shortcut: जब दोनों SP बराबर और percentages भी (x%), तो net loss = (x/10)² = (20/10)² = 4%।', '+20% वाले की CP = 960/1.20 = 800। −20% वाले की CP = 960/0.80 = 1200। कुल CP = 2000, कुल SP = 1920। Loss = 80/2000 = 4%। दिशा loss की होती है क्योंकि loss वाले की CP बड़ी है।', 'MEDIUM', array['profit-loss','two-articles-same-sp','net-profit-loss','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'No profit, no loss', 'न profit, न loss', false, 'Symmetric cancellation — +20% and −20% at the same SP do NOT cancel because the underlying CPs (800 and 1200) differ.', '+20% और −20% same SP पर cancel नहीं होते क्योंकि CPs (800 और 1200) अलग हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '4% loss', '4% loss', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '4% gain', '4% gain', false, 'Correct magnitude but wrong sign — with same SP and equal-% split, the heavier CP (loss side) dominates, so the net is always a LOSS.', 'Magnitude सही, sign गलत — same SP और equal % split में बड़ी CP (loss side) dominate करती है, net हमेशा LOSS।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '20% loss', '20% loss', false, 'Applied only the −20% loss side and ignored the +20% gain side entirely: reported the loss% as the overall P/L%.', 'सिर्फ −20% loss side लगाया, +20% gain side पूरी तरह छोड़ दिया: overall P/L% को loss% के बराबर मान लिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 26, 'An article is marked up by 40% above its cost and then sold after a 20% discount. Find the gain percentage.', 'एक वस्तु पर 40% markup लगाकर फिर 20% discount पर बेची गई। gain प्रतिशत क्या है?', 'Take CP = 100. MP = 140. SP = 140 × 0.80 = 112. Gain% = 12%. Shortcut: final/CP − 1 = 1.40 × 0.80 − 1 = 0.12 = 12%.', 'The markup inflates CP to MP; the discount deflates MP to SP. Net gain depends on whether (1 + markup)(1 − discount) is greater or less than 1. Here it''s 1.12, so 12% gain. Adding markup% and subtracting discount% is always wrong unless you explicitly use the compound-percentage formula a + b + (ab/100).', 'CP = 100 मानें। MP = 140। SP = 140 × 0.80 = 112। Gain% = 12%। Shortcut: (1.40 × 0.80) − 1 = 12%।', 'Markup CP से MP बढ़ाता है; discount MP से SP घटाता है। Net gain (1+markup)(1−discount) पर निर्भर — यहाँ 1.12 → 12% gain। Markup से discount सीधे घटाना गलत है जब तक compound formula न लगाएँ।', 'MEDIUM', array['profit-loss','markup','discount','successive-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20%', '20%', false, 'Subtracted directly: m − d = 40 − 20 = 20%. Ignored that markup uses CP as base (100) while discount uses MP as base (140).', 'सीधे m − d = 40 − 20 = 20% निकाला। Markup CP (100) पर, discount MP (140) पर — bases अलग।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '12%', '12%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '28%', '28%', false, 'Sign error on the cross-term: computed 40 − 20 + (40×20)/100 = 40 − 20 + 8 = 28. The correct formula is m − d − md/100 (minus sign on cross-term).', 'Cross-term का sign गलत: 40 − 20 + (40×20)/100 = 28 निकाला। सही formula m − d − md/100 है (− sign on cross-term)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '10%', '10%', false, 'Halved the naive difference (40 − 20 = 20) as a ''compounding dampener'': got 10%. True dampening = only the cross-term md/100 = 4, giving 16... actually 20 − 8 = 12%, not 10.', 'Naive अंतर (40 − 20 = 20) को आधा कर दिया (''compounding dampener'' सोचकर): 10% मिला। सही dampening केवल cross-term md/100 = 8 है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 27, 'A shopkeeper sells goods at cost price but uses a weight of 900g in place of 1 kg. What is his actual gain percentage?', 'एक दुकानदार cost price पर सामान बेचता है पर 1 kg की जगह 900g का बाट (weight) इस्तेमाल करता है। वास्तविक gain% क्या है?', 'Shortcut: gain% = (error / (true wt − error)) × 100 = (100/900) × 100 = 11.11%.', 'The merchant''s cost per true-gram stays the same, but he only delivers 900g while charging the price of 1000g. So he saves the cost of 100g for every 900g he actually gives. Gain percent is therefore 100/900 (the extra revenue divided by what was actually spent), not 100/1000 (which would be the fraction of the claimed weight).', 'shortcut: gain% = (error / (true wt − error)) × 100 = (100/900) × 100 = 11.11%।', 'Merchant true-gram की cost वही रखता है पर केवल 900g देता है और 1000g की कीमत वसूलता है। हर 900g पर 100g की cost बचाता है। Gain% = 100/900, न कि 100/1000।', 'MEDIUM', array['profit-loss','dishonest-merchant','weight-fraud','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '10%', '10%', false, 'Used shortfall 100 divided by claimed weight 1000: 100/1000 = 10%. The denominator must be what was actually delivered (900g), not claimed.', 'Shortfall 100 को claimed weight 1000 से भाग दिया: 100/1000 = 10%। Denominator delivered weight (900g) होगा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '11.11%', '11.11%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '9.09%', '9.09%', false, 'Divided shortfall 100 by 1100 (added shortfall to claimed weight by mistake): 100/1100 = 9.09%. Denominator is 900, not 1100.', 'Shortfall 100 को 1100 से भाग दिया (shortfall को claimed weight में जोड़ दिया): 100/1100 = 9.09%। Denominator 900 है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '12.5%', '12.5%', false, 'Assumed shortfall was 100 on a base of 800 (interpreted ''delivered 800g while claiming 1000g''): 100/800 = 12.5%. The actual delivered weight is 900g.', '800g को delivered weight मान लिया (shortfall 200g माना): 100/800 = 12.5%। सही delivered weight 900g है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 28, '10 kg of rice at ₹10 per kg is mixed with 10 kg at ₹20 per kg. The mixture is sold at ₹18 per kg. Find the gain percentage on the mixture.', '10 kg चावल ₹10 per kg वाला और 10 kg ₹20 per kg वाला मिलाकर mixture ₹18 per kg पर बेचा गया। mixture पर gain% क्या है?', 'Total CP = 10×10 + 10×20 = 100 + 200 = ₹300. Total SP = 20 × 18 = ₹360. Gain = 60. Gain% = 60/300 × 100 = 20%.', 'When two costs are mixed and sold at a single rate, total CP is the sum of the two inputs and total SP is (final per-unit rate × total units). Gain% is always on total CP, not on either input''s CP alone.', 'Total CP = 10×10 + 10×20 = 300। Total SP = 20×18 = 360। Gain = 60। Gain% = 60/300 × 100 = 20%।', 'दो costs mix होकर एक rate पर बिकते हैं: total CP = sum of inputs, total SP = per-unit rate × total units। Gain% कुल CP पर।', 'MEDIUM', array['profit-loss','mixture','gain-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '60%', '60%', false, 'Divided gain 60 by cheap-variety CP only (10 × 10 = 100): 60/100 = 60%. Denominator must be total mix CP = 300.', 'Gain 60 को सिर्फ cheap variety की CP (10 × 10 = 100) से भाग दिया: 60/100 = 60%। सही total mix CP 300।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '15%', '15%', false, 'Assumed total CP at the higher rate: 20 kg × ₹20 = ₹400 → 60/400 = 15%. Actual mix CP = 10×10 + 10×20 = 300.', 'Total CP को ऊँची rate पर मान लिया: 20 kg × ₹20 = ₹400 → 60/400 = 15%। सही mix CP = 10×10 + 10×20 = 300।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '16.67%', '16.67%', false, 'Divided gain 60 by total SP 360 (not CP 300): 60/360 = 16.67%. Gain% is always on CP.', 'Gain 60 को total SP 360 से भाग दिया: 60/360 = 16.67%। Gain% हमेशा CP पर।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 29, 'A trader buys a product for ₹500. He spends ₹50 on transport and sells it for ₹660. Find his gain percentage.', 'एक व्यापारी ₹500 में product खरीदता है, ₹50 transport पर खर्च करता है, और ₹660 में बेचता है। gain% क्या है?', 'Total CP = 500 + 50 = ₹550. Gain = 660 − 550 = 110. Gain% = 110/550 × 100 = 20%.', 'All overheads (transport, storage, packaging) are part of the cost price. Ignoring them inflates the apparent gain%. Always aggregate every pre-sale expense into CP before computing gain%.', 'Total CP = 500 + 50 = ₹550। Gain = 110। Gain% = 110/550 × 100 = 20%।', 'सारे overheads (transport, storage, packaging) CP में जुड़ते हैं। इन्हें भूलने पर apparent gain% बढ़ जाता है।', 'MEDIUM', array['profit-loss','overhead-cost','total-cost','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '32%', '32%', false, 'Ignored transport when computing CP: used gain 160 (= 660 − 500) over CP 500: 160/500 = 32%. Correct total cost = 500 + 50 = 550, gain = 110.', 'Transport छोड़ दिया: gain 160 (= 660 − 500) को CP 500 पर: 160/500 = 32%। सही total cost = 500 + 50 = 550, gain = 110।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '22%', '22%', false, 'Used correct gain 110 but ignored transport only in the denominator: 110/500 = 22%. Transport 50 must be included in CP, so 110/550 = 20%.', 'Gain 110 सही, पर denominator में transport छूट गया: 110/500 = 22%। Transport 50 CP में जोड़ना है: 110/550 = 20%।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '24%', '24%', false, 'Subtracted transport from CP instead of adding: 500 − 50 = 450; 110/450 = 24.4%. Transport is a cost — it ADDS to CP, not subtracts.', 'Transport को CP में से घटा दिया: 500 − 50 = 450; 110/450 = 24.4%। Transport cost है, यह CP में जुड़ती है।');
insert into public.test_sections (test_id, title_en, title_hi, question_count, display_order, subject_hint) values (v_t, 'General Intelligence & Reasoning', 'General Intelligence & Reasoning', 30, 3, 'reason') returning id into v_s;
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'Statements: All flowers are red. All red things are beautiful. Conclusions: I. All flowers are beautiful. II. Some beautiful things are flowers.', 'कथन: सभी flowers red हैं। सभी red चीज़ें beautiful हैं। निष्कर्ष: I. सभी flowers beautiful हैं। II. कुछ beautiful चीज़ें flowers हैं।', 'All flowers ⊆ red, all red ⊆ beautiful ⇒ all flowers ⊆ beautiful (transitive). I follows. From ''all flowers are beautiful'' and the existence of flowers, ''some beautiful are flowers'' follows (existential extraction). II follows. Hence both follow.', 'A universal affirmative chain (All A ⊆ B, all B ⊆ C) gives All A ⊆ C. From any universal ''all A are X'' with non-empty A, the particular ''some X are A'' is valid — this is called the existential import of universal statements.', 'All flowers ⊆ red, all red ⊆ beautiful ⇒ all flowers ⊆ beautiful (transitive)। I valid है। ''सभी flowers beautiful हैं'' से ''कुछ beautiful चीज़ें flowers हैं'' valid है (existential import)। II भी valid। दोनों follow करते हैं।', 'Universal affirmative chain (All A ⊆ B, all B ⊆ C) से All A ⊆ C। ''All A are X'' (A non-empty) से ''Some X are A'' valid (existential import)।', 'EASY', array['syllogism','reasoning','universal-affirmative','transitive','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I अनुसरण करता है', false, 'Conclusion II also follows: if all flowers are beautiful (and flowers exist), then at least some beautiful things are flowers — by particular-from-universal extraction.', 'II भी सही है: यदि सभी flowers beautiful हैं (और flowers मौजूद हैं), तो कुछ beautiful चीज़ें flowers होंगी।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II अनुसरण करता है', false, 'Conclusion I also follows: All flowers ⊆ All red ⊆ All beautiful gives All flowers ⊆ All beautiful directly (transitive chain of universals).', 'I भी valid है: सभी flowers ⊆ सभी red ⊆ सभी beautiful — universal transitive से All flowers ⊆ All beautiful।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both I and II follow', 'I और II दोनों अनुसरण करते हैं', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither I nor II follows', 'न I न II अनुसरण करता है', false, 'Both conclusions follow logically — flatly rejecting both ignores the valid universal-transitive chain.', 'दोनों conclusions valid हैं — दोनों को reject करना universal-transitive chain को ignore करना है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'Statements: All cats are mammals. No mammal is a fish. Conclusions: I. No cat is a fish. II. Some mammals are not cats.', 'कथन: सभी cats mammals हैं। कोई mammal fish नहीं है। निष्कर्ष: I. कोई cat fish नहीं है। II. कुछ mammals cats नहीं हैं।', 'Cats ⊆ mammals; mammals ∩ fish = ∅. Therefore cats ∩ fish = ∅. So I follows. II would require knowing that mammals strictly contains cats, but the premises allow mammals = cats.', 'Subset relations chain through disjoint relations: A ⊆ B and B ∩ C = ∅ ⇒ A ∩ C = ∅. But A ⊆ B does NOT imply ''some B are not A'' unless we additionally know A ⊊ B (proper subset). The premises here allow equality.', 'Cats ⊆ mammals; mammals ∩ fish = ∅ ⇒ cats ∩ fish = ∅। I valid। II के लिए mammals ⊋ cats चाहिए, पर premises equality allow करते हैं।', 'Subset और disjoint chain होते हैं: A ⊆ B और B ∩ C = ∅ ⇒ A ∩ C = ∅। पर A ⊆ B से ''कुछ B, A नहीं हैं'' नहीं निकलता (proper subset चाहिए)।', 'EASY', array['syllogism','reasoning','universal-negative','subset-disjoint','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I अनुसरण करता है', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II अनुसरण करता है', false, 'II is NOT necessarily true: if all mammals were cats (consistent with the premises), then no mammal would be a non-cat. The premises don''t rule that out.', 'II ज़रूरी नहीं: यदि सभी mammals cats हों (premises के साथ consistent), तो कोई mammal non-cat नहीं होगा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों अनुसरण करते हैं', false, 'I follows but II does not. Don''t infer ''some mammals are not cats'' from a one-way subset; mammals could equal cats.', 'I valid पर II invalid। एक-तरफ़ा subset से ''कुछ mammals cats नहीं'' नहीं निकलता।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II अनुसरण करता है', false, 'I follows: cats ⊆ mammals and mammals ∩ fish = ∅ ⇒ cats ∩ fish = ∅. Rejecting both ignores this valid chain.', 'I valid है: cats ⊆ mammals, mammals ∩ fish = ∅ ⇒ cats ∩ fish = ∅।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'Statements: Some pens are pencils. All pencils are erasers. Conclusions: I. Some pens are erasers. II. All erasers are pencils.', 'कथन: कुछ pens, pencils हैं। सभी pencils, erasers हैं। निष्कर्ष: I. कुछ pens, erasers हैं। II. सभी erasers, pencils हैं।', 'Some pens are pencils ⇒ at least one item is both pen and pencil. All pencils are erasers ⇒ that item is also an eraser ⇒ some pens are erasers. I follows. II is improper conversion of a universal affirmative — invalid.', 'Particular affirmative + universal affirmative gives particular affirmative on the other side: ''Some A are B'' + ''All B are C'' ⇒ ''Some A are C''. The converse of ''All B are C'' is NOT ''All C are B'' — universal affirmative does not validly convert.', '''कुछ pens pencils हैं'' से कम-से-कम एक चीज़ pen-और-pencil दोनों है। ''सभी pencils erasers हैं'' से वह eraser भी है ⇒ ''कुछ pens erasers हैं''। I valid। II universal affirmative का improper conversion।', 'Particular affirmative + universal affirmative ⇒ particular affirmative: ''Some A are B'' + ''All B are C'' ⇒ ''Some A are C''। ''All B are C'' का converse ''All C are B'' valid नहीं।', 'EASY', array['syllogism','reasoning','particular-affirmative','improper-conversion','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I अनुसरण करता है', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II अनुसरण करता है', false, 'II is improper conversion: ''All pencils are erasers'' does NOT mean ''All erasers are pencils''. Erasers could include non-pencils.', 'II improper conversion है: ''सभी pencils erasers हैं'' का मतलब ''सभी erasers pencils'' नहीं — erasers में non-pencils भी हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों अनुसरण करते हैं', false, 'I follows from chaining ''some pens are pencils'' with ''all pencils are erasers''. II is invalid (improper conversion of universal affirmative).', 'I valid है chain से। II improper conversion से invalid।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I does follow: those pens that are pencils (existing by ''some pens are pencils'') must also be erasers (by ''all pencils are erasers''), so ''some pens are erasers'' holds.', 'I valid है: ''कुछ pens जो pencils हैं'' सभी erasers होंगे, अतः ''कुछ pens erasers हैं'' सच है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'Statements: All teachers are educated. Some educated people are doctors. Conclusions: I. Some teachers are doctors. II. Some doctors are teachers.', 'कथन: सभी teachers educated हैं। कुछ educated लोग doctors हैं। निष्कर्ष: I. कुछ teachers doctors हैं। II. कुछ doctors teachers हैं।', 'Teachers ⊆ educated. Some educated are doctors — but the ''some'' might lie entirely outside teachers. So we cannot conclude that any teacher is a doctor or vice versa. Neither follows.', 'The classical fallacy of undistributed middle: when a particular statement involves the middle term, that middle term may not link the two extremes. Both ''all A are B'' and ''some B are C'' share B, but the ''some B'' could miss A entirely.', 'Teachers ⊆ educated। ''कुछ educated, doctors हैं'' — पर ये ''कुछ'' teachers के बाहर हो सकते हैं। न I न II।', 'Undistributed middle का classical fallacy: middle term particular में हो तो वह दोनों extremes को link नहीं करता।', 'MEDIUM', array['syllogism','reasoning','undistributed-middle','particular-affirmative','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I does NOT follow: the ''some educated people who are doctors'' might be entirely outside the teacher subset. Undistributed middle.', 'I valid नहीं: ''कुछ educated जो doctors हैं'' teacher subset के बाहर हो सकते हैं। Undistributed middle।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is the converse of I and equally invalid. The middle term ''educated'' is not distributed in either premise.', 'II, I का converse और उतना ही invalid है। Middle term ''educated'' किसी भी premise में distributed नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'Both fail by the same fallacy: the doctors mentioned could be educated non-teachers; teachers and doctors might not overlap at all.', 'दोनों एक ही fallacy से fail: doctors educated-non-teachers हो सकते हैं — teachers और doctors में overlap ज़रूरी नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', true, null, null);
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'Statements: All birds can fly. Penguins are birds. Conclusions: I. Penguins can fly. II. Some flying things are penguins.', 'कथन: सभी birds उड़ सकते हैं। Penguins birds हैं। निष्कर्ष: I. Penguins उड़ सकते हैं। II. कुछ उड़ने वाली चीज़ें penguins हैं।', 'Treat premises as true. All birds ⊆ flying things; penguins ⊆ birds ⇒ penguins ⊆ flying things ⇒ I follows. From ''penguins fly'' and ''penguins exist'', ''some flying things are penguins'' follows ⇒ II follows.', 'Syllogism asks you to treat the given premises as true, even if they conflict with real-world knowledge. The instruction ''take the statements to be true even if they seem to be at variance with commonly known facts'' is the syllogism cardinal rule.', 'Premises को सच मानें। All birds ⊆ flying; penguins ⊆ birds ⇒ penguins ⊆ flying ⇒ I valid। ''Penguins उड़ते हैं'' + ''penguins मौजूद हैं'' से II valid।', 'Syllogism में real-world से अलग premises को सच मानना है। यह syllogism का cardinal rule है।', 'EASY', array['syllogism','reasoning','treat-premises-as-true','modus-ponens','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'II also follows: from ''penguins fly'' + ''penguins exist'', ''some flying things are penguins'' is a valid existential extraction.', 'II भी valid: ''penguins उड़ते हैं'' + ''penguins मौजूद हैं'' से ''कुछ उड़ने वाले penguins हैं'' निकलता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'I follows by direct modus ponens: All birds fly, penguins are birds ⇒ penguins fly. Real-world knowledge that penguins don''t fly is irrelevant; treat premises as true.', 'I direct modus ponens से valid: सभी birds उड़ते हैं + penguins birds हैं ⇒ penguins उड़ते हैं। Real-world ज्ञान irrelevant; premises को सच मानें।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'Both follow under the syllogism rule: treat the given premises as true regardless of real-world facts.', 'Syllogism rule से दोनों valid हैं: premises को real-world से अलग सच मानें।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'Statements: No book is a magazine. Some magazines are journals. Conclusions: I. Some journals are not books. II. Some books are not journals.', 'कथन: कोई book magazine नहीं है। कुछ magazines journals हैं। निष्कर्ष: I. कुछ journals books नहीं हैं। II. कुछ books journals नहीं हैं।', 'Some magazines are journals ⇒ ∃x: x is magazine AND x is journal. ''No book is magazine'' ⇒ that x is not a book ⇒ that x is journal-and-not-book ⇒ some journals are not books. I follows. II talks about books and journals directly; nothing in premises forces a non-overlap there.', 'Combining a particular affirmative (''some B are J'') with a universal negative (''no Bk is B'') yields a particular negative (''some J are not Bk''). The other direction (''some Bk are not J'') is not forced.', '''कुछ magazines journals हैं'' ⇒ कोई item magazine AND journal है। ''कोई book magazine नहीं'' ⇒ वह item book नहीं ⇒ कुछ journals books नहीं। I valid। II के लिए premises books-journals पर कुछ नहीं कहते।', 'Particular affirmative + universal negative ⇒ particular negative। Reverse direction (II) force नहीं होता।', 'MEDIUM', array['syllogism','reasoning','particular-negative','complementary-pair','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is invalid: the premises say nothing about whether all books are or aren''t journals. Books could be journals (just not magazines).', 'II invalid: premises books और journals के बीच कोई direct constraint नहीं देते। Books, journals हो सकती हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'I follows but II does not. The premises do not constrain books-journals overlap directly.', 'I valid पर II invalid। Premises books-journals direct overlap पर कुछ नहीं कहते।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I does follow: ''some magazines are journals'' identifies items that are magazines AND journals; those items can''t be books (since no book is a magazine), so ''some journals are not books''.', 'I valid है: ''कुछ magazines journals हैं'' से magazine-AND-journal items हैं; ये books नहीं हो सकते (books, magazines नहीं), अतः ''कुछ journals books नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 6, 'Statements: All apples are red. All red are round. All round are sweet. Conclusions: I. All apples are sweet. II. Some sweet are apples.', 'कथन: सभी apples red हैं। सभी red round हैं। सभी round sweet हैं। निष्कर्ष: I. सभी apples sweet हैं। II. कुछ sweet, apples हैं।', 'Apples ⊆ red ⊆ round ⊆ sweet (transitive). I: all apples are sweet ✓. II: with apples non-empty, some sweet are apples ✓. Both follow.', 'A chain of universal affirmatives is transitive: A ⊆ B ⊆ C ⊆ D ⇒ A ⊆ D. Existential extraction from any ''all A are X'' (with A non-empty) yields ''some X are A''.', 'Apples ⊆ red ⊆ round ⊆ sweet (transitive)। I valid; II existential extraction से valid (apples non-empty)।', 'Universal affirmative chain transitive: A ⊆ B ⊆ C ⊆ D ⇒ A ⊆ D। Non-empty A से ''all A are X'' पर ''some X are A'' निकलता है।', 'MEDIUM', array['syllogism','reasoning','transitive-chain','three-statement','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'II also follows: from ''all apples are sweet'' and existence of apples, ''some sweet are apples'' is a valid existential extraction.', 'II भी valid: ''सभी apples sweet'' से (apples मौजूद मानकर) ''कुछ sweet apples हैं'' निकलता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'I follows from a three-step transitive chain. Rejecting I is rejecting transitivity of the universal affirmative.', 'I three-step transitive से valid है। I को reject करना universal affirmative की transitivity reject करना है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'Both follow logically; rejecting both ignores the universal-transitive chain and existential import.', 'दोनों valid; reject करना universal transitive और existential import दोनों ignore करना है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 7, 'Statements: Some students are clever. All clever people are successful. Conclusions: I. Some students are successful. II. All successful people are students.', 'कथन: कुछ students clever हैं। सभी clever लोग successful हैं। निष्कर्ष: I. कुछ students successful हैं। II. सभी successful लोग students हैं।', 'Some students are clever ⇒ ∃ student who is clever. All clever are successful ⇒ that student is successful ⇒ some students are successful. I follows. II would require successful ⊆ students, but premises only give clever ⊆ successful — successful could include non-clever non-students.', '''Some A are B'' + ''All B are C'' ⇒ ''Some A are C''. Converting ''all B are C'' to ''all C are B'' is improper — the standard fallacy of illicit conversion of universal affirmative.', '''कुछ students clever'' से कोई student clever है। ''All clever successful'' से वह student successful ⇒ ''कुछ students successful''। II के लिए successful ⊆ students चाहिए — premises नहीं देते।', 'Some A are B + All B are C ⇒ Some A are C। ''All B are C'' को ''All C are B'' में convert करना improper है।', 'EASY', array['syllogism','reasoning','improper-conversion','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is improper conversion of ''All clever people are successful'' via the chained ''students are successful'' step. Universal affirmatives don''t convert validly.', 'II improper conversion है। Universal affirmative convert valid नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'I follows but II is improper conversion. Successful people might include non-students; nothing in premises rules that out.', 'I valid पर II improper conversion। Successful में non-students हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I does follow: those students who are clever (existing by ''some students are clever'') are also successful (by ''all clever are successful'').', 'I valid: ''कुछ students जो clever हैं'' सभी successful हैं ⇒ ''कुछ students successful हैं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'Statements: All squares are rectangles. All rectangles are quadrilaterals. Conclusions: I. All quadrilaterals are squares. II. Some quadrilaterals are squares.', 'कथन: सभी squares rectangles हैं। सभी rectangles quadrilaterals हैं। निष्कर्ष: I. सभी quadrilaterals squares हैं। II. कुछ quadrilaterals squares हैं।', 'Squares ⊆ rectangles ⊆ quadrilaterals. So all squares are quadrilaterals. With squares non-empty, ''some quadrilaterals are squares'' (existential extraction). II follows. I requires the converse, which is invalid.', 'From any universal affirmative ''all A are B'' with A non-empty, the particular ''some B are A'' follows by existential import. The full converse ''all B are A'' does NOT.', 'Squares ⊆ rectangles ⊆ quadrilaterals ⇒ सभी squares quadrilaterals हैं। Non-empty squares से ''कुछ quadrilaterals squares'' (existential import)। II valid। I converse — invalid।', 'Non-empty A वाले ''all A are B'' से ''some B are A'' (existential import से) निकलता है, पर ''all B are A'' नहीं।', 'MEDIUM', array['syllogism','reasoning','subset-inversion','existential-import','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is improper conversion of universal affirmative — squares ⊆ quadrilaterals does NOT mean quadrilaterals ⊆ squares.', 'I improper conversion: squares ⊆ quadrilaterals का मतलब quadrilaterals ⊆ squares नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'II follows by existential import; I is improper conversion. Don''t accept ''all C are A'' from ''all A are C''.', 'II valid पर I improper conversion।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'II follows: with squares non-empty (subset of rectangles, etc.), ''some quadrilaterals are squares'' is a valid existential extraction.', 'II valid: squares non-empty ⇒ ''कुछ quadrilaterals squares हैं'' existential import से।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 9, 'Statements: Some bottles are jars. No jar is a bucket. Conclusions: I. No bottle is a bucket. II. Some bottles are not buckets.', 'कथन: कुछ bottles jars हैं। कोई jar bucket नहीं है। निष्कर्ष: I. कोई bottle bucket नहीं है। II. कुछ bottles, buckets नहीं हैं।', 'Some bottles are jars ⇒ ∃ x: bottle AND jar. No jar is bucket ⇒ x is not a bucket ⇒ some bottles are not buckets. II follows. I claims NO bottle is a bucket, but the premises only constrain bottle-AND-jar items.', 'From ''some A are B'' and ''no B is C'', we get ''some A are not C'' — but NOT ''no A is C''. The universal negative requires all A to be excluded from C; we only know the AB-overlap is excluded.', '''कुछ bottles, jars'' से कोई item bottle AND jar। ''कोई jar, bucket नहीं'' ⇒ वह bucket नहीं ⇒ ''कुछ bottles buckets नहीं''। II valid। I के लिए सब bottles excluded होने चाहिए — premises नहीं देते।', 'Some A are B + No B is C ⇒ Some A are not C। पर No A is C नहीं — सिर्फ AB-overlap excluded है।', 'MEDIUM', array['syllogism','reasoning','particular-negative','existential-extraction','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I claims NO bottle is a bucket — too strong. Only the bottles-that-are-jars are forced to be non-buckets; other bottles could be buckets.', 'I बहुत strong: केवल वे bottles जो jars हैं non-buckets हैं; बाकी bottles, buckets हो सकती हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'II follows but I overstates. The premises only constrain bottles-that-are-jars to be non-buckets, not all bottles.', 'II valid पर I overstates। Premises सिर्फ bottle-AND-jar items को non-buckets बनाती हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'II follows: those bottles that are jars (existing) cannot be buckets; therefore ''some bottles are not buckets''.', 'II valid: bottle-जो-jar हैं वे buckets नहीं हो सकते ⇒ ''कुछ bottles buckets नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'Statements: All A are B. Some B are C. Conclusions: I. Some A are C. II. Some C are not A.', 'कथन: सभी A, B हैं। कुछ B, C हैं। निष्कर्ष: I. कुछ A, C हैं। II. कुछ C, A नहीं हैं।', 'All A ⊆ B. Some B are C — but those C''s might be in A or outside it; both consistent with premises. Therefore neither ''some A are C'' nor ''some C are not A'' is forced.', 'When the middle term B is universal in one premise and particular in the other, but the ''some B'' could be any sub-portion of B (including or excluding A), no conclusion connecting A and C is forced. This is the canonical undistributed-middle setup.', 'All A ⊆ B। ''कुछ B, C'' — पर वे A के अंदर या बाहर हो सकते हैं; दोनों premises के साथ consistent। न ''कुछ A, C'' न ''कुछ C, A नहीं'' force होते हैं।', 'Middle term एक premise में universal, दूसरे में particular हो, पर ''some B'' any sub-portion (A में या बाहर) हो सकता है, तो A-C connection force नहीं — canonical undistributed-middle।', 'MEDIUM', array['syllogism','reasoning','undistributed-middle','neither-follows','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is undistributed middle: the ''some B that are C'' might lie outside the A subset entirely.', 'I undistributed middle: ''कुछ B जो C हैं'' A के बाहर हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is also not forced: ''some C that are B'' might all be A as well — premises allow that.', 'II force नहीं: ''कुछ C जो B हैं'' सब A भी हो सकते हैं — premises allow करती हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'Both fail: classic undistributed-middle case where the particular term (C) is independent of A in the premises.', 'दोनों fail: classic undistributed-middle case।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', true, null, null);
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 11, 'Statements: All cups are plates. All plates are dishes. Conclusions: I. Some dishes are cups. II. All dishes are cups.', 'कथन: सभी cups plates हैं। सभी plates dishes हैं। निष्कर्ष: I. कुछ dishes cups हैं। II. सभी dishes cups हैं।', 'Cups ⊆ plates ⊆ dishes. With cups non-empty, some dishes are cups ⇒ I follows. II requires dishes ⊆ cups, which is the invalid converse.', 'Existential import gives ''some C are A'' from ''all A are C'' (A non-empty) — that''s I. The full converse ''all C are A'' is invalid — that''s II.', 'Cups ⊆ plates ⊆ dishes। Non-empty cups से ''कुछ dishes cups'' (I valid)। II के लिए dishes ⊆ cups चाहिए — invalid converse।', 'Non-empty A से ''all A are C'' पर ''some C are A'' (existential import) — I valid। ''All C are A'' invalid converse — II invalid।', 'MEDIUM', array['syllogism','reasoning','improper-conversion','particular-vs-universal','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is improper conversion of the universal affirmative chain. The chain only gives cups ⊆ dishes, NOT dishes ⊆ cups.', 'II improper conversion: chain से cups ⊆ dishes मिलता है, dishes ⊆ cups नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'I follows by existential import; II is the invalid converse. Don''t claim ''all C are A'' from ''all A are C''.', 'I valid (existential import); II improper conversion।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I follows: cups non-empty ⇒ some dishes are cups (existential extraction).', 'I valid: cups non-empty ⇒ ''कुछ dishes cups'' existential import से।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 12, 'Statements: No politician is honest. Some honest people are leaders. Conclusions: I. Some leaders are not politicians. II. Some politicians are not leaders.', 'कथन: कोई politician honest नहीं है। कुछ honest लोग leaders हैं। निष्कर्ष: I. कुछ leaders politicians नहीं हैं। II. कुछ politicians leaders नहीं हैं।', 'Some honest are leaders ⇒ ∃ x: honest AND leader. No politician is honest ⇒ x is not a politician ⇒ x is leader-and-not-politician ⇒ some leaders are not politicians. I follows. II concerns politicians vs. leaders, but premises don''t link them directly.', 'Particular affirmative + universal negative through a shared term yields a particular negative on the OTHER pair. Direction matters: II asks about politicians-leaders, where the premises give no such link.', '''कुछ honest, leaders'' से honest-AND-leader items हैं। ''कोई politician honest नहीं'' ⇒ ये items politicians नहीं ⇒ ''कुछ leaders politicians नहीं''। I valid। II politicians-leaders direct link के बिना force नहीं।', 'Particular affirmative + universal negative shared term से दूसरी pair पर particular negative। Direction मायने रखती है।', 'HARD', array['syllogism','reasoning','particular-negative','asymmetric','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is not forced: all politicians could simultaneously be leaders (just not honest); premises don''t constrain politicians-leaders overlap.', 'II force नहीं: सभी politicians, leaders हो सकते हैं (बस honest नहीं); premises politicians-leaders overlap पर silent।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'I follows from honest+leader items being non-politicians. II is not forced.', 'I valid; II force नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I does follow: those honest people who are leaders cannot be politicians (no politician is honest), so some leaders are not politicians.', 'I valid: honest+leader items politicians नहीं हो सकते (कोई politician honest नहीं), अतः ''कुछ leaders politicians नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 13, 'Statements: All P are Q. Some Q are R. No R is S. Conclusions: I. Some P are R. II. Some Q are not S.', 'कथन: सभी P, Q हैं। कुछ Q, R हैं। कोई R, S नहीं है। निष्कर्ष: I. कुछ P, R हैं। II. कुछ Q, S नहीं हैं।', 'I: needs P-R link via Q. P ⊆ Q gives info about P, but ''some Q are R'' could be the non-P portion of Q. So I not forced. II: ∃ x: Q AND R; no R is S ⇒ x is not S ⇒ x is Q-and-not-S ⇒ some Q are not S. II follows.', 'Multi-step syllogisms succeed only when the middle terms are properly distributed. Here R links Q and S validly (II) but Q''s particular subset that overlaps R is independent of P, blocking I.', 'I के लिए P-R link via Q चाहिए, पर ''कुछ Q, R'' P के बाहर हो सकते हैं ⇒ undistributed middle। II valid: ''कुछ Q, R'' + ''कोई R, S नहीं'' ⇒ Q-AND-R items S नहीं ⇒ ''कुछ Q, S नहीं''।', 'Multi-step syllogism में middle terms properly distributed होने चाहिए। यहाँ R, Q-S को link करता है (II) पर Q-R overlap P से independent (I block)।', 'HARD', array['syllogism','reasoning','three-statement','undistributed-middle','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is undistributed middle: the ''some Q that are R'' might be entirely outside P even though all P are Q. Specifically, P could be a sub-portion of Q that misses R.', 'I undistributed middle: ''कुछ Q जो R हैं'' P के बाहर हो सकते हैं भले all P ⊆ Q।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'II follows but I has the undistributed-middle problem.', 'II valid पर I undistributed-middle से fail।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'II follows: ''some Q are R'' + ''no R is S'' ⇒ those Q-AND-R items are not S ⇒ some Q are not S.', 'II valid: ''कुछ Q, R'' + ''कोई R, S नहीं'' ⇒ Q-AND-R items, S नहीं ⇒ ''कुछ Q, S नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 14, 'Statements: Some pencils are pens. Some pens are markers. Conclusions: I. Some pencils are markers. II. Some markers are pencils.', 'कथन: कुछ pencils, pens हैं। कुछ pens, markers हैं। निष्कर्ष: I. कुछ pencils, markers हैं। II. कुछ markers, pencils हैं।', 'Two particular premises share term ''pens''. The ''some pens that are pencils'' subset and the ''some pens that are markers'' subset can be disjoint in pen-space, blocking any pencil-marker conclusion.', 'Classical syllogism rule: from two particular premises, no valid conclusion follows. This is because particular statements don''t distribute the middle term, leaving both extremes independent.', 'दोनों particulars ''pens'' term share करते हैं। ''कुछ pens जो pencils'' और ''कुछ pens जो markers'' pen-space में disjoint हो सकते हैं — pencil-marker conclusion block।', 'Classical rule: दो particular premises से valid conclusion नहीं — particulars middle term distribute नहीं करते।', 'MEDIUM', array['syllogism','reasoning','two-particular','undistributed-middle','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I cannot be derived from two particulars. The ''some pens that are pencils'' and ''some pens that are markers'' might be entirely different subsets of pens.', 'I two particulars से नहीं निकलता: ''कुछ pens जो pencils हैं'' और ''कुछ pens जो markers हैं'' अलग subsets हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is the converse of I and equally invalid. Two particulars don''t produce a connecting particular.', 'II, I का converse, उतना ही invalid। दो particulars से connecting particular नहीं निकलता।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'Standard rule: a syllogism with two particular premises produces no valid conclusion (both fail by undistributed middle).', 'Standard rule: दो particular premises से कोई valid conclusion नहीं — दोनों undistributed middle से fail।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', true, null, null);
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 15, 'Statements: All children are innocent. Some innocent people are wise. Conclusions: I. Some children are wise. II. All wise people are children.', 'कथन: सभी children innocent हैं। कुछ innocent लोग wise हैं। निष्कर्ष: I. कुछ children wise हैं। II. सभी wise लोग children हैं।', 'Children ⊆ innocent. Some innocent are wise — but they could be exactly the non-children innocent people. So I not forced. II would require wise ⊆ children, never stated.', 'Universal subset + particular overlap with the supersetdoes NOT propagate to the subset (undistributed middle). Always check if the ''some'' statement could be entirely outside the subset.', 'Children ⊆ innocent। ''कुछ innocent, wise'' children के बाहर हो सकते हैं ⇒ I force नहीं। II के लिए wise ⊆ children चाहिए — premises नहीं।', 'Universal subset + superset पर particular overlap subset पर propagate नहीं होता (undistributed middle)।', 'MEDIUM', array['syllogism','reasoning','undistributed-middle','improper-conversion','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is undistributed middle: ''some innocent who are wise'' might be entirely outside the children subset of innocent people.', 'I undistributed middle: ''कुछ innocent जो wise'' children के बाहर हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II requires wise ⊆ children; nothing in premises forces that. Improper conversion of multiple steps.', 'II के लिए wise ⊆ children चाहिए; premises नहीं देते।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'Both fail: I by undistributed middle, II by lack of premise support.', 'दोनों fail: I undistributed middle से, II premise-support के बिना।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', true, null, null);
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 16, 'Statements: No fish is a bird. All birds fly. Conclusions: I. No fish flies. II. Some flying things are not fish.', 'कथन: कोई fish, bird नहीं है। सभी birds उड़ते हैं। निष्कर्ष: I. कोई fish उड़ता नहीं है। II. कुछ उड़ने वाली चीज़ें fish नहीं हैं।', 'Birds ⊆ flying things; fish ∩ birds = ∅. Existential import: some flying things are birds (birds non-empty), and those are not fish ⇒ some flying things are not fish (II). I would require all flying things to be non-fish, which the premises don''t establish.', 'Universal negatives don''t propagate strongly. From ''no fish is a bird'' and ''all birds fly'', we get ''some flying things are not fish'' (existential import) but NOT ''no fish flies'' — the latter requires fish to be excluded from ALL flying things, not just birds.', 'Birds ⊆ flying; fish ∩ birds = ∅। Existential import: ''कुछ flying birds हैं'' और birds, fish नहीं ⇒ ''कुछ flying, fish नहीं'' (II)। I के लिए सभी flying things से fish excluded होने चाहिए — premises नहीं देते।', 'Universal negative strongly propagate नहीं होते। ''कोई fish, bird नहीं'' और ''सभी birds उड़ते'' से ''कुछ flying, fish नहीं'' तो निकलता है पर ''कोई fish उड़ता नहीं'' नहीं।', 'MEDIUM', array['syllogism','reasoning','universal-negative','existential-import','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I claims no fish flies, but premises say ''no fish is a bird'' and ''birds fly''. Fish could fly without being birds (consider mythical flying fish that aren''t classed as birds).', 'I overstates: ''कोई fish bird नहीं'' और ''birds उड़ते हैं'' से ''fish उड़ नहीं सकते'' force नहीं — fish bird हुए बिना उड़ सकती हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'II follows from existential import on birds (birds non-empty ⇒ some flyers are birds; birds aren''t fish ⇒ some flyers aren''t fish). I overstates the constraint.', 'II existential import से valid; I overstates।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'II follows: birds exist (assumed non-empty) and they fly, and they''re not fish ⇒ some flying things are not fish.', 'II valid: birds (non-empty) उड़ते हैं और fish नहीं हैं ⇒ ''कुछ flying things, fish नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 17, 'Statements: All artists are creative. Some creative people are scientists. Conclusions: I. Some artists are scientists. II. Either some artists are scientists OR no artist is a scientist.', 'कथन: सभी artists creative हैं। कुछ creative लोग scientists हैं। निष्कर्ष: I. कुछ artists scientists हैं। II. या तो कुछ artists scientists हैं, या कोई artist scientist नहीं है।', 'I depends on whether artist-scientist overlap is non-empty; premises don''t decide. II (an ''either A or not-A'' for the artist-scientist relation) is a tautology, always true. So II follows; I does not necessarily.', 'Complementary-pair conclusions (''either some A are B OR no A is B'') are tautologies — they always follow because they exhaust the logical possibilities. They appear in exam questions to test whether students recognize the tautology.', 'I के लिए artist-scientist overlap non-empty चाहिए; premises silent। II (''या तो कुछ A, B हैं या कोई A, B नहीं'') tautology — हमेशा valid।', 'Complementary pairs (''या तो कुछ A, B हैं या कोई A, B नहीं'') tautology होते हैं — हमेशा valid। Exam में इन्हें पहचानना है।', 'HARD', array['syllogism','reasoning','complementary-pair','either-or','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is undistributed middle and not forced. Premises allow artist-scientist overlap to be empty.', 'I undistributed middle से force नहीं। Artist-scientist overlap empty हो सकता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'II is the tautological ''either-or'' covering all possibilities — always valid. I alone is not.', 'II tautological ''either-or'' है — हमेशा valid। I अकेला नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'II is logically vacuous (covers all cases) but technically follows. I doesn''t.', 'II tautological पर technically valid; I नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 18, 'Statements: All managers are leaders. Some leaders are coaches. Conclusions: I. Some managers are coaches. II. No manager is a coach.', 'कथन: सभी managers, leaders हैं। कुछ leaders, coaches हैं। निष्कर्ष: I. कुछ managers, coaches हैं। II. कोई manager coach नहीं है।', 'I and II are complementary: ''Some managers are coaches'' vs. ''No manager is a coach''. Exactly one must be true. Without further premise constraint, neither alone is forced, but their disjunction is.', 'When two conclusions form a complementary pair (existential ''some are'' vs universal ''none are''), exactly one must be true even if you can''t determine which. The exam-correct option is ''Either I or II follows''.', 'I और II complementary: ''कुछ managers, coaches'' vs ''कोई manager, coach नहीं''। ठीक एक सच होगा। ''Either I or II'' option सही।', 'Complementary pair (existential ''कुछ हैं'' vs universal ''कोई नहीं'') में ठीक एक सच होगा। ''Either I or II follows'' option exam में सही।', 'MEDIUM', array['syllogism','reasoning','complementary-pair','either-or-explicit','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is not forced (undistributed middle on ''leaders''). The ''some leaders who are coaches'' might miss managers entirely.', 'I undistributed middle: ''कुछ leaders, coaches'' managers से miss कर सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is also not forced: managers could overlap with coaches via the leader bridge; premises don''t rule it out.', 'II force नहीं: managers, coaches के साथ leader bridge से overlap कर सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Either I or II follows', 'या तो I या II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I and II are complementary (one says ''some are'', the other ''none are''); together they exhaust all cases ⇒ at least one must be true.', 'I और II complementary हैं (''कुछ हैं'' vs ''कोई नहीं''); मिलकर सभी cases cover करते हैं ⇒ कम-से-कम एक सच।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 19, 'Statements: Some doctors are surgeons. All surgeons are skilled. No skilled person is lazy. Conclusions: I. No doctor is lazy. II. Some doctors are not lazy.', 'कथन: कुछ doctors, surgeons हैं। सभी surgeons skilled हैं। कोई skilled person lazy नहीं है। निष्कर्ष: I. कोई doctor lazy नहीं है। II. कुछ doctors lazy नहीं हैं।', 'Some doctors are surgeons ⇒ ∃ x: doctor AND surgeon. All surgeons are skilled ⇒ x is skilled. No skilled is lazy ⇒ x is not lazy. So x is doctor-and-not-lazy ⇒ some doctors are not lazy. II follows. I overstates by claiming all doctors are non-lazy.', 'Three-statement chains compose: a particular at the start propagates as a particular at the end. The chain ''doctor → surgeon → skilled → not lazy'' applies to the doctor-surgeon overlap, not all doctors.', '''कुछ doctors, surgeons'' से ∃ doctor-AND-surgeon। सभी surgeons skilled, कोई skilled lazy नहीं ⇒ वह lazy नहीं ⇒ ''कुछ doctors lazy नहीं''। II valid। I सभी doctors पर overstates।', 'तीन-statement chain compose होती है: शुरू में particular ⇒ अंत में particular। Chain doctor-AND-surgeon overlap पर लगती है, सभी doctors पर नहीं।', 'HARD', array['syllogism','reasoning','three-statement','particular-negative','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I claims NO doctor is lazy, but premises only constrain doctors-who-are-surgeons. Other doctors could be lazy.', 'I overstates: सिर्फ doctor-AND-surgeon items lazy नहीं हैं; बाकी doctors lazy हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'II follows but I overstates. The premises only constrain doctor-surgeons, not all doctors.', 'II valid पर I overstates।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'II does follow: those doctors who are surgeons (existing) are skilled (per premise 2) and not lazy (per premise 3) ⇒ some doctors are not lazy.', 'II valid: ''कुछ doctors, surgeons'' से surgeon-doctors हैं; वे skilled हैं ⇒ lazy नहीं ⇒ ''कुछ doctors lazy नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'Statements: All cars are vehicles. Some cars are red. Conclusions: I. Some vehicles are red. II. Some red things are vehicles.', 'कथन: सभी cars, vehicles हैं। कुछ cars red हैं। निष्कर्ष: I. कुछ vehicles red हैं। II. कुछ red चीज़ें vehicles हैं।', 'Some cars are red ⇒ some red are cars (symmetry). Cars ⊆ vehicles ⇒ some red are vehicles AND some vehicles are red. Both follow.', 'Particular affirmative is symmetric: ''some A are B'' ⇔ ''some B are A''. When you also have a universal affirmative on one side, the particular propagates through.', '''कुछ cars red'' से ''कुछ red, cars'' (symmetry)। Cars ⊆ vehicles ⇒ ''कुछ red, vehicles'' AND ''कुछ vehicles, red''। दोनों valid।', 'Particular affirmative symmetric है: ''some A are B'' ⇔ ''some B are A''। Universal affirmative के साथ particular propagate होता है।', 'EASY', array['syllogism','reasoning','particular-affirmative','symmetry','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'II also follows by symmetry of ''some'': ''some A are B'' is logically equivalent to ''some B are A''.', 'II भी valid: ''some A are B'' = ''some B are A'' (symmetry of ''some'')।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'I follows just as strongly. Some cars are red ⇒ some red are cars ⇒ (cars ⊆ vehicles) some red are vehicles AND some vehicles are red.', 'I उतना ही valid। ''कुछ cars red'' से ''कुछ red, cars'' ⇒ ''कुछ red, vehicles'' AND ''कुछ vehicles red''।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'Both follow trivially via symmetric particular and universal-affirmative chaining.', 'दोनों valid: symmetric particular और universal-affirmative chain से।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 21, 'Statements: All ducks are birds. Some birds are pets. Conclusions: I. Some ducks are pets. II. Some pets are not ducks.', 'कथन: सभी ducks, birds हैं। कुछ birds, pets हैं। निष्कर्ष: I. कुछ ducks, pets हैं। II. कुछ pets, ducks नहीं हैं।', 'Either some ducks are pets (case I) or no ducks are pets, in which case all the bird-pets must be non-duck birds, so some pets are not ducks (case II). Exactly one of I, II must be true.', 'When two conclusions span the existence/non-existence of an overlap, they form a complementary pair. The exam answer is ''Either I or II follows'' even though neither is forced individually.', 'या तो ''कुछ ducks, pets'' (case I) या ''कोई duck, pet नहीं'', और बाद वाले case में bird-pets non-duck birds होंगे ⇒ ''कुछ pets, ducks नहीं'' (case II)। ठीक एक सच।', 'जब दो conclusions overlap के existence/non-existence पर हों, complementary pair बनती है। Exam में ''Either I or II follows''।', 'MEDIUM', array['syllogism','reasoning','complementary-pair','either-or','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is undistributed middle: ''some birds are pets'' could miss the ducks subset entirely.', 'I undistributed middle: ''कुछ birds, pets'' ducks subset miss कर सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II requires a pet that is not a duck. The premises allow all pets to be ducks (since ducks ⊆ birds and the bird-pets could be exactly the ducks).', 'II के लिए कोई pet जो duck नहीं हो — premises allow करते हैं कि सभी pets ducks हों।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Either I or II follows', 'या तो I या II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I and II are NOT exact complements but cover both possibilities of duck-pet overlap (existing or not). Exactly one must hold given that some birds are pets.', 'I और II complementary हैं duck-pet overlap के दोनों cases पर — कम-से-कम एक सच।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 22, 'Statements: No A is B. All B are C. Conclusions: I. Some C are not A. II. No A is C.', 'कथन: कोई A, B नहीं है। सभी B, C हैं। निष्कर्ष: I. कुछ C, A नहीं हैं। II. कोई A, C नहीं है।', 'All B ⊆ C; no A is B. With B non-empty, ∃ B-AND-C items, which are not A ⇒ some C are not A. I follows. II claims no A is C, but A could intersect C in the C-minus-B region.', 'Universal negatives propagate to existential negatives via existential import on the linking universal. They do NOT propagate to universal negatives across the chain — that requires further constraints.', 'All B ⊆ C; no A is B। B non-empty ⇒ B-AND-C items, A नहीं ⇒ ''कुछ C, A नहीं''। I valid। II के लिए A सभी C से excluded होने चाहिए — premises नहीं देते।', 'Universal negatives existential negatives में propagate होते हैं linking universal के existential import से। Universal negatives chain across नहीं propagate होते।', 'HARD', array['syllogism','reasoning','universal-negative','existential-import','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II overstates: A could overlap with C-minus-B portion. The premise ''no A is B'' only excludes A from B, not from all of C.', 'II overstates: A, C-minus-B portion में हो सकता है। ''कोई A, B नहीं'' केवल B से excludes करता है, सभी C से नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', false, 'I follows by existential import on B (B non-empty ⇒ B ⊆ C ⇒ some C are B; those C-B items aren''t A ⇒ some C are not A). II overstates.', 'I valid (existential import); II overstates।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I follows: ''all B are C'' + ''no A is B'' ⇒ those B''s that are C are not A ⇒ some C are not A.', 'I valid: ''all B are C'' + ''no A is B'' ⇒ B-AND-C items, A नहीं ⇒ ''कुछ C, A नहीं''।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 23, 'Statements: All scientists are intelligent. All intelligent people are curious. Some curious people are not scientists. Conclusions: I. Some curious people are intelligent. II. Some intelligent people are not scientists.', 'कथन: सभी scientists intelligent हैं। सभी intelligent लोग curious हैं। कुछ curious लोग scientists नहीं हैं। निष्कर्ष: I. कुछ curious intelligent हैं। II. कुछ intelligent scientists नहीं हैं।', 'I: All intelligent ⊆ curious; intelligent non-empty (since scientists exist) ⇒ some curious are intelligent ✓. II: Suppose all intelligent are scientists. Then all curious-non-scientists are non-intelligent. But this requires that some curious people exist outside the intelligent set (curious-not-intelligent), which the premises don''t rule in or out. Subtle case: II is actually ''follows in possibility'' but conventional exam answer takes existential extraction from intelligent giving non-scientist intelligent items only when intelligent ⊋ scientists, which the premises don''t force. Convention: take II as following if interpreted with existential import on ''some curious are not scientists'' → those curious might be intelligent or not; conventional exam answer often marks II as following.', 'Three-statement syllogisms can have nuanced answers. Always check existential import carefully and consider whether ''some'' extracts validly through the chain.', 'I: सभी intelligent ⊆ curious; intelligent non-empty ⇒ ''कुछ curious intelligent'' valid। II: ''कुछ curious, scientists नहीं'' से अगर intelligent non-scientists हों तो ''कुछ intelligent, scientists नहीं'' valid।', 'तीन-statement syllogism में existential import और ''some'' extraction carefully check करें।', 'HARD', array['syllogism','reasoning','three-statement','existential-import','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'II also follows: ''some curious are not scientists'' could include intelligent-non-scientists OR non-intelligent-non-scientists. We need to verify the intelligent case.', 'II भी संभव; specific items का type verify करना है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'I also follows: scientists ⊆ intelligent ⊆ curious ⇒ all intelligent ⊆ curious ⇒ some curious are intelligent (existential import).', 'I भी valid: existential import से।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Both follow', 'दोनों', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'Both follow: I by existential import, II is more subtle but follows because the curious-non-scientists must include some intelligent non-scientists (or else all intelligent would be scientists, contradicting curious-not-scientists existence).', 'दोनों valid; I existential import से, II subtle reasoning से।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 24, 'Statements: All books are journals. Some journals are magazines. Conclusions: I. Some books are magazines. II. Some magazines are not books.', 'कथन: सभी books, journals हैं। कुछ journals, magazines हैं। निष्कर्ष: I. कुछ books, magazines हैं। II. कुछ magazines, books नहीं हैं।', 'Either some books are magazines (the journal-magazine overlap intersects books) — case I — or none are (the overlap misses books) — in which case the magazines among journals are non-books, so some magazines are not books (case II). Exactly one holds.', 'Complementary ''either-or'' patterns appear when premises constrain two sets only loosely, leaving the overlap question to two possibilities. The exam-correct answer is ''Either I or II follows''.', 'या तो ''कुछ books, magazines'' (case I) या ''कोई book, magazine नहीं'' (case II के लिए magazines books से बाहर)। ठीक एक सच।', 'Premises overlap loose रखें तो complementary ''either-or'' patterns बनते हैं। Exam में ''Either I or II follows''।', 'MEDIUM', array['syllogism','reasoning','complementary-pair','either-or','cbt1-full-mock']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Only I follows', 'केवल I', false, 'I is undistributed middle. The ''some journals that are magazines'' could miss the books subset.', 'I undistributed middle: ''कुछ journals, magazines'' books subset miss कर सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Only II follows', 'केवल II', false, 'II is also not forced: all magazines could be books (a subset of journals).', 'II force नहीं: सभी magazines, books हो सकते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Either I or II follows', 'या तो I या II', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Neither follows', 'न I न II', false, 'I and II form complementary cases on whether the journal-magazine overlap intersects with books or not. Exactly one must hold.', 'I और II complementary हैं — journal-magazine overlap books से intersect करता है या नहीं। ठीक एक सच।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 25, 'If today is Monday, what day will it be after 45 days?', 'यदि आज Monday है, तो 45 days बाद कौन सा day होगा?', '45 mod 7 = 3. Move 3 days from Monday; the day is Thursday. Therefore, answer = Thursday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Thursday.', '45 mod 7 = 3। Monday से 3 days आगे बढ़ें; day Thursday होगा। अतः answer = Thursday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Thursday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Thursday', 'Thursday', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Friday', 'Friday', false, 'Counted today as day 1 and shifted one extra day. After 45 days means add 45 mod 7.', 'आज को day 1 count करके एक extra day shift कर दिया। 45 days बाद का मतलब 45 mod 7 add करना है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Saturday', 'Saturday', false, 'Reduced 45 by 7 incorrectly and moved two days too far.', '45 को 7 से गलत reduce किया और two days आगे चले गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Monday', 'Monday', false, 'Assumed the same day repeats without checking 45 mod 7. Same day occurs only if remainder is 0.', '45 mod 7 check किए बिना same day मान लिया। Same day तभी होगा जब remainder 0 हो।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 26, 'If today is Wednesday, what day will it be after 31 days?', 'यदि आज Wednesday है, तो 31 days बाद कौन सा day होगा?', '31 mod 7 = 3. Move 3 days from Wednesday; the day is Saturday. Therefore, answer = Saturday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Saturday.', '31 mod 7 = 3। Wednesday से 3 days आगे बढ़ें; day Saturday होगा। अतः answer = Saturday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Saturday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
