insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 27, 'If today is Friday, what day will it be after 64 days?', 'यदि आज Friday है, तो 64 days बाद कौन सा day होगा?', '64 mod 7 = 1. Move 1 days from Friday; the day is Saturday. Therefore, answer = Saturday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Saturday.', '64 mod 7 = 1। Friday से 1 days आगे बढ़ें; day Saturday होगा। अतः answer = Saturday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Saturday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
