insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 28, 'If today is Sunday, what day will it be after 100 days?', 'यदि आज Sunday है, तो 100 days बाद कौन सा day होगा?', '100 mod 7 = 2. Move 2 days from Sunday; the day is Tuesday. Therefore, answer = Tuesday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Tuesday.', '100 mod 7 = 2। Sunday से 2 days आगे बढ़ें; day Tuesday होगा। अतः answer = Tuesday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Tuesday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
