insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 29, 'If today is Tuesday, what day will it be after 17 days?', 'यदि आज Tuesday है, तो 17 days बाद कौन सा day होगा?', '17 mod 7 = 3. Move 3 days from Tuesday; the day is Friday. Therefore, answer = Friday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Friday.', '17 mod 7 = 3। Tuesday से 3 days आगे बढ़ें; day Friday होगा। अतः answer = Friday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Friday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
